import * as THREE from "three";
import { GLTFLoader } from "three/addons/loaders/GLTFLoader.js";

const canvas = document.createElement("canvas");
document.body.appendChild(canvas);
const renderer = new THREE.WebGLRenderer({ canvas, antialias: false });
renderer.setSize(512, 512);
const scene = new THREE.Scene();
const camera = new THREE.PerspectiveCamera(75, 1, 0.1, 500);
camera.position.set(10, 8, 10);
camera.lookAt(0, 0, 0);

// voxels
const blockGeo = new THREE.BoxGeometry(1, 1, 1);
for (let x = -3; x <= 3; x++) {
  for (let z = -3; z <= 3; z++) {
    const block = new THREE.Mesh(blockGeo, new THREE.MeshLambertMaterial({ color: 0x4caf50 }));
    block.position.set(x, 0, z);
    scene.add(block);
  }
}

// particles
const positions = new Float32Array(500 * 3);
for (let i = 0; i < 500; i++) {
  positions[i * 3] = (Math.random() - 0.5) * 20;
  positions[i * 3 + 1] = Math.random() * 10;
  positions[i * 3 + 2] = (Math.random() - 0.5) * 20;
}
const pGeo = new THREE.BufferGeometry();
pGeo.setAttribute("position", new THREE.BufferAttribute(positions, 3));
scene.add(new THREE.Points(pGeo, new THREE.PointsMaterial({ color: 0xffffaa, size: 0.1 })));

scene.add(new THREE.AmbientLight(0xffffff, 0.6));
const sun = new THREE.DirectionalLight(0xffffff, 1);
sun.position.set(5, 10, 5);
scene.add(sun);

// gltf prop
const loader = new GLTFLoader();
const gltfJson = {
  asset: { version: "2.0" },
  scenes: [{ nodes: [0] }],
  scene: 0,
  nodes: [{ mesh: 0, translation: [0, 2, 0] }],
  meshes: [{ primitives: [{ attributes: { POSITION: 0 }, indices: 1 }] }],
  accessors: [
    { bufferView: 0, componentType: 5126, count: 8, type: "VEC3", max: [0.5, 0.5, 0.5], min: [-0.5, -0.5, -0.5] },
    { bufferView: 1, componentType: 5123, count: 36, type: "SCALAR" },
  ],
  bufferViews: [
    { buffer: 0, byteOffset: 0, byteLength: 96 },
    { buffer: 0, byteOffset: 96, byteLength: 72 },
  ],
  buffers: [{ byteLength: 168, uri: "data:application/octet-stream;base64," +
    "AAAAPwAAAD8AAAA/AAAAPwAAAD8AAAC/AAAAPwAAAL8AAAC/AAAAPwAAAL8AAAA/" +
    "AACAPwAAAD8AAAA/AACAPwAAAD8AAAC/AACAPwAAAL8AAAC/AACAPwAAAL8AAAA/" +
    "AACAvwAAAD8AAAA/AACAvwAAAD8AAAC/AACAvwAAAL8AAAC/AACAvwAAAL8AAAA/" +
    "AAAAPwAAAD8AAAA/AAAAPwAAAD8AAAC/AAAAPwAAAL8AAAC/AAAAPwAAAL8AAAA/" +
    "AAAAAAADAAAAAAUAAgAGAAUABgAHAAUABwAGAAcACAAIAAcACQAIAAoACAALAAoACwAMAAoADAA=" }],
};
const gltf = await loader.parseAsync(JSON.stringify(gltfJson), "");
scene.add(gltf.scene);

renderer.render(scene, camera);

(window as unknown as { __POC_RESULT__: Record<string, unknown> }).__POC_RESULT__ = {
  totalObjects: scene.children.length,
  drawCalls: renderer.info.render.calls,
  hasVoxels: true,
  hasParticles: true,
  hasGltf: gltf.scene.children.length >= 0,
};
(window as unknown as { __POC_READY__: boolean }).__POC_READY__ = true;

