### source/tests/harness.ts
```ts
import * as esbuild from "esbuild";
import { chromium, type Browser } from "playwright";

let browser: Browser | null = null;

async function getBrowser(): Promise<Browser> {
  if (!browser) {
    browser = await chromium.launch();
  }
  return browser;
}

export type PocRunResult = Record<string, unknown>;

/**
 * Bundle TypeScript POC entry and execute in headless Chromium with real WebGL.
 */
export async function runPocInBrowser(entryPath: string): Promise<PocRunResult> {
  const built = await esbuild.build({
    entryPoints: [entryPath],
    bundle: true,
    format: "esm",
    write: false,
    platform: "browser",
    target: "es2022",
  });

  const script = built.outputFiles[0]?.text;
  if (!script) {
    throw new Error(`esbuild produced no output for ${entryPath}`);
  }

  const html = `<!DOCTYPE html><html><body><script type="module">${script}</script></body></html>`;
  const b = await getBrowser();
  const page = await b.newPage();
  try {
    await page.setContent(html);
    await page.waitForFunction(() => (window as unknown as { __POC_READY__?: boolean }).__POC_READY__ === true, null, {
      timeout: 30_000,
    });
    const result = await page.evaluate(() => (window as unknown as { __POC_RESULT__?: PocRunResult }).__POC_RESULT__);
    if (!result) {
      throw new Error("POC did not set window.__POC_RESULT__");
    }
    return result;
  } finally {
    await page.close();
  }
}

export async function closeBrowser(): Promise<void> {
  if (browser) {
    await browser.close();
    browser = null;
  }
}

