### source/tests/live.test.ts
```ts
import { afterAll, describe, expect, it } from "vitest";
import { fileURLToPath } from "node:url";
import { dirname, join } from "node:path";
import { closeBrowser, runPocInBrowser } from "./harness.ts";

const pocEntry = join(dirname(fileURLToPath(import.meta.url)), "../src/poc.ts");

afterAll(async () => {
  await closeBrowser();
});

describe("[Live behavioral test] Capstone", () => {
  it("renders with real WebGL in headless Chromium", async () => {
    const result = await runPocInBrowser(pocEntry);
    expect(result.totalObjects as number).toBeGreaterThan(10);
    expect(result.hasVoxels).toBe(true);
    expect(result.hasParticles).toBe(true);
    expect(result.drawCalls as number).toBeGreaterThan(0);
  });
});

