 *   5. Config surface: all knobs in agent.config.ts; enabledTools gates the tool list
 *
 * To recustomize: edit agent.config.ts only — no core-logic edits.
 */
import { defineAgent } from '@flue/runtime'
import { agentConfig } from '../agent.config.ts'
import { getWeather } from '../tools/get-weather.ts'
import { getAirQuality } from '../tools/get-air-quality.ts'
import { getWorldTime } from '../tools/get-world-time.ts'

const ALL_TOOLS = [getWeather, getAirQuality, getWorldTime]

// Build active tool list from config surface
const activeTools = ALL_TOOLS.filter(
  (t) => agentConfig.enabledTools[t.name] !== false
)

export default defineAgent(() => ({
  model: agentConfig.model,
  instructions: agentConfig.persona,
  tools: activeTools,
}))

