### source/config-loader.mjs
```mjs
/**
 * config-loader.mjs
 *
 * Reusable typed config/env loader + request-body validator helper.
 * Zod 4.4.3, Node ESM.
 *
 * This module exports:
 *   - AppConfigSchema — a Zod schema for an app config object with branded
 *     and coerced fields.
 *   - load(raw) — parses a raw config object; returns typed value on success,
 *     throws a formatted ConfigError on failure.
 *   - validateRequestBody(schema, body) — returns { status: 200, data } on
 *     success or { status: 422, errors: [...] } on failure.
 */

import { z } from 'zod';

// --- Branded type: Port is a number brand ---
const PortBrand = z.number().int().min(1).max(65535).brand('Port');

// --- AppConfigSchema ---
// Fields:
//   host      — non-empty string
//   port      — coerced from string or number; branded as Port
//   dbUrl     — non-empty string matching a URL-ish prefix
//   logLevel  — one of the four allowed log levels
//   maxRetries — optional, defaults to 3 via transform; coerced from string/number
export const AppConfigSchema = z.object({
  host: z.string().min(1, { message: 'host must not be empty' }),
  port: z.coerce.number().int().min(1).max(65535).brand('Port'),
  dbUrl: z.string().url({ message: 'dbUrl must be a valid URL' }),
  logLevel: z.enum(['debug', 'info', 'warn', 'error']),
  maxRetries: z.coerce.number().int().min(0).max(10).optional().default(3),
});

/** TypeScript-style inferred type (JSDoc only — no tsc needed at runtime) */
// type AppConfig = z.infer<typeof AppConfigSchema>

// --- ConfigError ---
export class ConfigError extends Error {
  /** @param {string} message - human-readable formatted error */
  /** @param {import('zod').ZodIssue[]} issues - raw ZodError.issues */
  constructor(message, issues) {
    super(message);
    this.name = 'ConfigError';
    this.issues = issues;
  }
}

/**
 * Format ZodError.issues into a human-readable summary.
 * @param {import('zod').ZodIssue[]} issues
 * @returns {string}
 */
function formatIssues(issues) {
  return issues
    .map((issue) => {
      const path = issue.path.length > 0 ? issue.path.join('.') : '(root)';
      return `  [${path}] ${issue.message}`;
    })
    .join('\n');
}

/**
 * Load and validate a raw config object against AppConfigSchema.
 * Returns the typed config on success; throws ConfigError on failure.
 *
 * @param {unknown} raw - the raw config input (e.g. from process.env or a file)
 * @returns {z.infer<typeof AppConfigSchema>}
 */
export function load(raw) {
  const result = AppConfigSchema.safeParse(raw);
  if (!result.success) {
    const formatted = formatIssues(result.error.issues);
    throw new ConfigError(
      `Invalid application config:\n${formatted}`,
      result.error.issues
    );
  }
  return result.data;
}

/**
 * Validate an HTTP request body against any Zod schema.
 * Returns { status: 200, data } on success.
 * Returns { status: 422, errors: [{path, message},...] } on failure.
 *
 * @template T
 * @param {import('zod').ZodType<T>} schema
 * @param {unknown} body
 * @returns {{ status: 200, data: T } | { status: 422, errors: Array<{path: string, message: string}> }}
 */
export function validateRequestBody(schema, body) {
  const result = schema.safeParse(body);
  if (!result.success) {
    return {
      status: 422,
      errors: result.error.issues.map((issue) => ({
        path: issue.path.length > 0 ? issue.path.join('.') : '(root)',
        message: issue.message,
      })),
    };
  }
  return { status: 200, data: result.data };
}

