### source/config-loader.test.mjs
```mjs
/**
 * config-loader.test.mjs  — GREEN version
 *
 * Proves: load(invalid) throws ConfigError; load(valid) returns typed config;
 * validateRequestBody(schema, bad) returns {status:422, errors};
 * validateRequestBody(schema, good) returns {status:200, data}.
 *
 * Run: node --test config-loader.test.mjs
 */

import { describe, it } from 'node:test';
import assert from 'node:assert/strict';
import { z } from 'zod';
import { load, validateRequestBody, ConfigError, AppConfigSchema } from './config-loader.mjs';

// --- Fixtures ---

const VALID_CONFIG = {
  host: 'localhost',
  port: '8080',       // coerced string → number
  dbUrl: 'https://db.example.com/myapp',
  logLevel: 'info',
  maxRetries: '5',    // coerced string → number
};

const INVALID_CONFIG_MISSING_FIELDS = {
  // host is missing entirely
  port: 'not-a-number',   // will fail coercion
  dbUrl: 'not-a-url',     // not a valid URL
  logLevel: 'verbose',    // not in enum
  // maxRetries omitted — should default to 3
};

const RequestBodySchema = z.object({
  username: z.string().min(3, { message: 'username must be at least 3 characters' }),
  age: z.number().int().min(0).max(120),
  email: z.email({ error: 'Must be a valid email address' }),
});

// -----------------------------------------------------------
// Tests
// -----------------------------------------------------------

describe('L-capstone — typed config loader + request-body validator', () => {

  // ----------------------------------------------------------
  // load() — valid config
  // ----------------------------------------------------------

  it('load(validConfig) returns typed object with coerced fields', () => {
    const config = load(VALID_CONFIG);
    assert.equal(config.host, 'localhost');
    assert.equal(config.port, 8080);          // coerced from string '8080'
    assert.equal(config.logLevel, 'info');
    assert.equal(config.maxRetries, 5);       // coerced from string '5'
  });

  it('load(validConfig) defaults maxRetries to 3 when omitted', () => {
    const withoutRetries = { ...VALID_CONFIG };
    delete withoutRetries.maxRetries;
    const config = load(withoutRetries);
    assert.equal(config.maxRetries, 3);
  });

  // ----------------------------------------------------------
  // load() — invalid config
  // ----------------------------------------------------------

  it('load(invalidConfig) throws ConfigError', () => {
    // Correct assertion: load() throws ConfigError for invalid config.
    assert.throws(
      () => load(INVALID_CONFIG_MISSING_FIELDS),
      (err) => {
        assert.ok(err instanceof ConfigError, 'should throw ConfigError');
        return true;
      }
    );
  });

  it('load(invalidConfig) ConfigError.issues is non-empty', () => {
    let caughtError;
    try {
      load(INVALID_CONFIG_MISSING_FIELDS);
    } catch (err) {
      caughtError = err;
    }
    assert.ok(caughtError instanceof ConfigError, 'should throw ConfigError');
    assert.ok(Array.isArray(caughtError.issues) && caughtError.issues.length > 0,
      'ConfigError.issues should be non-empty');
  });

  it('load(invalidConfig) formatted error message lists field paths', () => {
    let msg;
    try {
      load(INVALID_CONFIG_MISSING_FIELDS);
    } catch (err) {
      msg = err.message;
    }
    assert.ok(msg && msg.includes('Invalid application config'), 'message should have header');
    // 'host' missing → should mention [host]
    assert.ok(msg.includes('[host]'), `message should mention [host], got: ${msg}`);
  });

  // ----------------------------------------------------------
  // validateRequestBody()
  // ----------------------------------------------------------

  it('validateRequestBody — valid body returns {status:200, data}', () => {
    const body = { username: 'alice', age: 30, email: 'alice@example.com' };
    const result = validateRequestBody(RequestBodySchema, body);
    assert.equal(result.status, 200);
    assert.deepEqual(result.data, body);
  });

  it('validateRequestBody — invalid body returns {status:422, errors}', () => {
    // Correct assertion: bad input produces 422 with errors array.
    const badBody = { username: 'ab', age: -1, email: 'not-an-email' };
    const result = validateRequestBody(RequestBodySchema, badBody);
    assert.equal(result.status, 422);
    assert.ok(Array.isArray(result.errors) && result.errors.length > 0);
  });

  it('validateRequestBody — errors array has correct path/message shape', () => {
    const badBody = { username: 'ab', age: -1, email: 'not-an-email' };
    const result = validateRequestBody(RequestBodySchema, badBody);
    assert.equal(result.status, 422);
    assert.ok(Array.isArray(result.errors) && result.errors.length > 0);
    const usernameErr = result.errors.find((e) => e.path === 'username');
    assert.ok(usernameErr, 'should have error for username');
    assert.ok(usernameErr.message.includes('3'), 'username error mentions min length');
  });

  // ----------------------------------------------------------
  // Live evidence unit: real ZodError.issues from AppConfigSchema
  // ----------------------------------------------------------

  it('AppConfigSchema.safeParse(invalid) issues array — live evidence unit', () => {
    const result = AppConfigSchema.safeParse(INVALID_CONFIG_MISSING_FIELDS);
    assert.equal(result.success, false);
    assert.ok(result.error instanceof z.ZodError);
    // At minimum: host missing, port coercion fail, dbUrl not url, logLevel invalid enum
    assert.ok(result.error.issues.length >= 3,
      `Expected >= 3 issues, got ${result.error.issues.length}: ${JSON.stringify(result.error.issues)}`);
  });

});

