#!/usr/bin/env node
// Assertion script for L8 capstone web chat POC.
// Proves: health 200, unauth 401, authed session start, stream event delivery.
// Usage: node assert.mjs [base_url] [basic_pass]
// Defaults to localhost:3018 with ROUTE_AUTH_BASIC_PASSWORD env var.

import assert from "node:assert/strict";

const BASE = process.argv[2] ?? "http://localhost:3018";
const PASS = process.argv[3] ?? process.env.ROUTE_AUTH_BASIC_PASSWORD ?? "testpass123";

async function main() {
  console.log(`\nAssert target: ${BASE}`);

  // 1. Health check (always public)
  console.log("\n[1] GET /eve/v1/health");
  const healthRes = await fetch(`${BASE}/eve/v1/health`);
  console.log("  status:", healthRes.status);
  const healthBody = await healthRes.json();
  console.log("  body:", JSON.stringify(healthBody));
  assert.equal(healthRes.status, 200, "health should be 200");
  assert.ok(healthBody.ok, "health.ok should be true");

  // 2. POST /eve/v1/session without auth -> 401
  console.log("\n[2] POST /eve/v1/session (no auth) -> expect 401");
  const unauthRes = await fetch(`${BASE}/eve/v1/session`, {
    method: "POST",
    headers: { "content-type": "application/json" },
    body: JSON.stringify({ message: "hello" }),
  });
  console.log("  status:", unauthRes.status);
  assert.equal(unauthRes.status, 401, "unauthenticated request should be 401");

  // 3. POST /eve/v1/session with httpBasic auth -> sessionId
  console.log("\n[3] POST /eve/v1/session (with basic auth) -> expect sessionId");
  const creds = Buffer.from(`operator:${PASS}`).toString("base64");
  const sessionRes = await fetch(`${BASE}/eve/v1/session`, {
    method: "POST",
    headers: {
      "content-type": "application/json",
      authorization: `Basic ${creds}`,
    },
    body: JSON.stringify({ message: "What is the weather in London?" }),
  });
  console.log("  status:", sessionRes.status);
  const sessionBody = await sessionRes.json();
  console.log("  body:", JSON.stringify(sessionBody));
  // Eve returns 202 Accepted for session start (async workflow kick-off)
  assert.ok(
    sessionRes.status === 200 || sessionRes.status === 202,
    `authed session start should be 200 or 202, got ${sessionRes.status}`
  );
  assert.ok(sessionBody.sessionId, "should return sessionId");
  assert.ok(sessionBody.ok, "should return ok:true");

  const sessionId = sessionBody.sessionId;

  // 4. Stream events from the session
  console.log(`\n[4] GET /eve/v1/session/${sessionId}/stream -> expect NDJSON events`);
  const streamRes = await fetch(`${BASE}/eve/v1/session/${sessionId}/stream`, {
    headers: { authorization: `Basic ${creds}` },
  });
  console.log("  stream status:", streamRes.status);
  assert.equal(streamRes.status, 200, "stream should be 200");

  const events = [];
  // Read the NDJSON stream line-by-line; stop at message.completed or after timeout
  const reader = streamRes.body.getReader();
  const decoder = new TextDecoder();
  let buf = "";
  const deadline = Date.now() + 30000; // 30s max
  outer: while (Date.now() < deadline) {
    const { done, value } = await reader.read();
    if (done) break;
    buf += decoder.decode(value, { stream: true });
    const parts = buf.split("\n");
    buf = parts.pop() ?? "";
    for (const line of parts) {
      const trimmed = line.trim();
      if (!trimmed) continue;
      try {
        const evt = JSON.parse(trimmed);
        events.push(evt);
        if (evt.type === "message.completed") break outer;
      } catch {
        // ignore non-JSON lines
      }
    }
  }
  reader.cancel().catch(() => {});

  console.log(`  events received: ${events.length}`);
  events.forEach((e, i) => console.log(`  [${i}] type=${e.type}`));

  assert.ok(events.length > 0, "should receive at least one stream event");

  const hasTurnStarted = events.some((e) => e.type === "turn.started");
  const hasMessageCompleted = events.some((e) => e.type === "message.completed");
  assert.ok(hasTurnStarted || hasMessageCompleted, "should have turn or message events");

  // Check for tool call (get_weather)
  const toolEvents = events.filter(
    (e) => e.type === "actions.requested" || e.type === "action.completed"
  );
  const textEvents = events.filter((e) => e.type === "text.delta");
  console.log(`\n  tool-related events: ${toolEvents.length}`);
  console.log(`  text delta events: ${textEvents.length}`);

  const finalText = textEvents.map((e) => e.delta ?? "").join("");
  if (finalText) {
    console.log(`  assistant text: "${finalText.slice(0, 200)}"`);
  }

  console.log("\nAll assertions PASSED.");
}

main().catch((err) => {
  console.error("\nAssertion FAILED:", err.message ?? err);
  process.exit(1);
});

