### source/test/run-and-assert.mjs
```mjs
/**
 * Integration test for L2 capstone agent POC.
 *
 * RED phase: Asserts incorrect expected output (Python content for Eiffel Tower file)
 *            → test FAILS, proving the assertion is meaningful.
 * GREEN phase: Asserts correct expected output (Eiffel Tower content)
 *              → test PASSES, proving the real model + tool pipeline works.
 *
 * Usage:
 *   RED:   node test/run-and-assert.mjs red
 *   GREEN: node test/run-and-assert.mjs green
 *   BOTH:  node test/run-and-assert.mjs both
 */

import { execFile } from 'node:child_process';
import { promisify } from 'node:util';
import { writeFileSync } from 'node:fs';
import { resolve, dirname } from 'node:path';
import { fileURLToPath } from 'node:url';

const execFileAsync = promisify(execFile);
const __dirname = dirname(fileURLToPath(import.meta.url));
const projectRoot = resolve(__dirname, '..');

async function runWorkflow(payload) {
  console.log(`\nRunning workflow with payload: ${JSON.stringify(payload)}`);
  const { stdout, stderr } = await execFileAsync(
    'npx',
    ['flue', 'run', 'read-and-summarize', '--target', 'node', '--payload', JSON.stringify(payload)],
    {
      cwd: projectRoot,
      env: { ...process.env },
      timeout: 120_000,
    },
  );
  console.log('--- stderr (events) ---');
  console.log(stderr);
  console.log('--- stdout (result JSON) ---');
  console.log(stdout);

  let result;
  try {
    result = JSON.parse(stdout.trim());
  } catch {
    throw new Error(`Could not parse workflow result as JSON. stdout: ${stdout}`);
  }
  return { result, stderr };
}

function assert(condition, message) {
  if (!condition) {
    console.error(`ASSERTION FAILED: ${message}`);
    process.exitCode = 1;
    throw new Error(`ASSERTION FAILED: ${message}`);
  }
  console.log(`  PASS: ${message}`);
}

// ─────────────────────────────────────────────────────────────────────────────
// RED test: asserts the wrong thing — that the summary mentions "Python"
// when we actually read the Eiffel Tower file. This MUST fail.
// ─────────────────────────────────────────────────────────────────────────────
async function runRedTest() {
  console.log('\n========== RED TEST: Asserting WRONG expected content ==========');
  console.log('We assert "Python" appears in summary of input.txt (Eiffel Tower).');
  console.log('This MUST FAIL to prove the test is meaningful.\n');

  const { result, stderr } = await runWorkflow({ filename: 'input.txt' });

  console.log('\nResult:', JSON.stringify(result, null, 2));
  console.log('\nRED assertion: summary should mention "Python" (deliberately wrong)');

  if (result.summary.toLowerCase().includes('python')) {
    console.log('RED TEST: PASSED assertion (UNEXPECTED — Eiffel Tower file contains Python?!)');
    console.log('WARNING: RED test should not pass like this!');
    process.exitCode = 0;
  } else {
    console.log('RED TEST: ASSERTION FAILED (CORRECT — "Python" not in Eiffel Tower summary)');
    console.log('RED correctly fails — test logic is sound.');
    process.exitCode = 1;
  }

  return { result, stderr };
}

// ─────────────────────────────────────────────────────────────────────────────
// GREEN test: asserts the real correct results
// ─────────────────────────────────────────────────────────────────────────────
async function runGreenTest() {
  console.log('\n========== GREEN TEST: Asserting CORRECT expected content ==========\n');

  // Test 1: input.txt — Eiffel Tower
  console.log('--- Test 1: input.txt (Eiffel Tower) ---');
  const { result: r1, stderr: e1 } = await runWorkflow({ filename: 'input.txt' });

  console.log('\nResult:', JSON.stringify(r1, null, 2));
  assert(typeof r1.summary === 'string', 'result.summary is a string');
  assert(r1.summary.length > 20, `summary is non-trivial (length=${r1.summary.length})`);
  assert(
    r1.summary.toLowerCase().includes('eiffel') ||
      r1.summary.toLowerCase().includes('tower') ||
      r1.summary.toLowerCase().includes('paris'),
    `summary mentions Eiffel Tower or Paris (got: "${r1.summary.substring(0, 120)}")`,
  );
  assert(r1.toolCalled === true, 'toolCalled flag is true');
  // Check that events show tool_call
  assert(
    e1.includes('tool_call') || e1.includes('read_file'),
    `stderr events contain tool_call or read_file evidence (found: ${e1.includes('tool_call') ? 'tool_call' : ''} ${e1.includes('read_file') ? 'read_file' : ''})`,
  );
  console.log('Test 1: ALL ASSERTIONS PASSED\n');

  // Test 2 (regression): second.txt — Python
  console.log('--- Test 2: second.txt (Python — regression check) ---');
  const { result: r2, stderr: e2 } = await runWorkflow({ filename: 'second.txt' });

  console.log('\nResult:', JSON.stringify(r2, null, 2));
  assert(typeof r2.summary === 'string', 'result.summary is a string');
  assert(r2.summary.length > 20, `summary is non-trivial (length=${r2.summary.length})`);
