    r2.summary.toLowerCase().includes('python') ||
      r2.summary.toLowerCase().includes('programming') ||
      r2.summary.toLowerCase().includes('guido'),
    `summary mentions Python or programming (got: "${r2.summary.substring(0, 120)}")`,
  );
  assert(r2.toolCalled === true, 'toolCalled flag is true');
  console.log('Test 2: ALL ASSERTIONS PASSED\n');

  return {
    test1: { result: r1, stderr: e1 },
    test2: { result: r2, stderr: e2 },
  };
}

// ─────────────────────────────────────────────────────────────────────────────
// Main
// ─────────────────────────────────────────────────────────────────────────────
const mode = process.argv[2] || 'both';

try {
  if (mode === 'red') {
    await runRedTest();
  } else if (mode === 'green') {
    await runGreenTest();
  } else {
