```mjs
/**
 * Capstone: OAuth 2.1-protected Streamable HTTP server
 * Adapted from L14 — static bearer token gate.
 * Exported as a factory so the test can start/stop it programmatically.
 */
import express from "express";
import { randomUUID } from "node:crypto";
import { McpServer } from "@modelcontextprotocol/sdk/server/mcp.js";
import { StreamableHTTPServerTransport } from "@modelcontextprotocol/sdk/server/streamableHttp.js";
import { createMcpExpressApp } from "@modelcontextprotocol/sdk/server/express.js";
import {
  mcpAuthMetadataRouter,
  getOAuthProtectedResourceMetadataUrl,
} from "@modelcontextprotocol/sdk/server/auth/router.js";
import { requireBearerAuth } from "@modelcontextprotocol/sdk/server/auth/middleware/bearerAuth.js";
import { InvalidTokenError } from "@modelcontextprotocol/sdk/server/auth/errors.js";
import { z } from "zod";

// Static bearer token (test-only; never logged)
const VALID_TOKEN = "secret-static-token";

const tokenVerifier = {
  async verifyAccessToken(token) {
    if (token !== VALID_TOKEN) {
      throw new InvalidTokenError("Invalid or unknown token");
    }
    return {
      token,
      clientId: "poc-client",
      scopes: ["mcp:tools"],
      expiresAt: Math.floor(Date.now() / 1000) + 3600,
    };
  },
};

function makeServer() {
  const srv = new McpServer(
    { name: "capstone-oauth-http", version: "1.0.0" },
    { capabilities: {} }
  );

  srv.registerTool(
    "whoami",
    {
      title: "Who Am I",
      description: "Returns the authenticated client identity",
      inputSchema: {},
    },
    async (_args, extra) => {
      const clientId = extra?.authInfo?.clientId ?? "unauthenticated";
      return { content: [{ type: "text", text: `clientId: ${clientId}` }] };
    }
  );

  srv.registerTool(
    "ping",
    {
      title: "Ping",
      description: "Returns pong with a message",
      inputSchema: { msg: z.string().optional().describe("Optional message") },
    },
    async ({ msg }) => ({
      content: [{ type: "text", text: `pong: ${msg ?? "hello"}` }],
    })
  );

  return srv;
}

/**
 * Start the OAuth HTTP server.
 * Returns { httpServer, baseUrl, close }
 */
export async function startOAuthServer() {
  const app = express();
  app.use(express.json());

  // Listen on a random free port
  const httpServer = app.listen(0);
  await new Promise((resolve) => httpServer.once("listening", resolve));
  const { port } = httpServer.address();

  const SERVER_URL = new URL(`http://localhost:${port}/mcp`);

  const oauthMetadata = {
    issuer: `http://localhost:${port}`,
    authorization_endpoint: `http://localhost:${port}/oauth/authorize`,
    token_endpoint: `http://localhost:${port}/oauth/token`,
    response_types_supported: ["code"],
    code_challenge_methods_supported: ["S256"],
  };

  // RS-only metadata (RFC 9728 PRM)
  app.use(
    mcpAuthMetadataRouter({
      oauthMetadata,
      resourceServerUrl: SERVER_URL,
      scopesSupported: ["mcp:tools"],
      resourceName: "Capstone OAuth MCP Server",
    })
  );

  const authMiddleware = requireBearerAuth({
    verifier: tokenVerifier,
    requiredScopes: ["mcp:tools"],
    resourceMetadataUrl: getOAuthProtectedResourceMetadataUrl(SERVER_URL),
  });

  const sessions = new Map();

  app.all("/mcp", authMiddleware, async (req, res) => {
    try {
      const sessionId = req.headers["mcp-session-id"];

      if (req.method === "POST") {
        const body = req.body;
        const isInit = body?.method === "initialize";

        if (isInit || !sessionId) {
          const transport = new StreamableHTTPServerTransport({
            sessionIdGenerator: () => randomUUID(),
            onsessioninitialized: (sid) => sessions.set(sid, { transport, server: srv }),
            onsessionclosed: (sid) => sessions.delete(sid),
          });
          const srv = makeServer();
          // Pass authInfo to tool handlers
          transport.onrequest = (request) => {
            request._meta = { ...request._meta, authInfo: req.auth };
          };
          await srv.connect(transport);
          await transport.handleRequest(req, res, body);
          return;
        }

        const session = sessions.get(sessionId);
        if (!session) return res.status(404).json({ error: "Session not found" });
        session.transport.onrequest = (request) => {
          request._meta = { ...request._meta, authInfo: req.auth };
        };
        await session.transport.handleRequest(req, res, body);
        return;
      }

      if (req.method === "GET") {
        if (!sessionId) return res.status(400).json({ error: "Missing Mcp-Session-Id" });
        const session = sessions.get(sessionId);
        if (!session) return res.status(404).json({ error: "Session not found" });
        await session.transport.handleRequest(req, res);
        return;
      }

      if (req.method === "DELETE") {
        if (!sessionId) return res.status(400).json({ error: "Missing Mcp-Session-Id" });
        const session = sessions.get(sessionId);
        if (!session) return res.status(404).json({ error: "Session not found" });
        await session.transport.handleRequest(req, res);
        sessions.delete(sessionId);
        return;
      }

      res.status(405).json({ error: "Method not allowed" });
    } catch (err) {
      if (!res.headersSent) res.status(500).json({ error: String(err.message) });
    }
  });

  return {
    httpServer,
    baseUrl: SERVER_URL.href,
    port,
    close: () => new Promise((resolve, reject) => httpServer.close((err) => err ? reject(err) : resolve())),
  };
}

