// Reset-aware backoff — copy from L5 for capstone self-containment.
export function parseRateLimitHeaders(headers) {
  const parse = (v) => (v !== null ? parseInt(v, 10) : null);
  return {
    limit: parse(headers.get('x-rate-limit-limit')),
    remaining: parse(headers.get('x-rate-limit-remaining')),
    reset: parse(headers.get('x-rate-limit-reset')),
  };
}
export function msUntilReset(resetUnixTimestamp, nowMs = Date.now()) {
  if (resetUnixTimestamp === null || resetUnixTimestamp === undefined) return 60_000;
  return Math.max(resetUnixTimestamp * 1000 - nowMs, 1000);
}
export function isRateLimitLow(remaining, threshold = 10) {
  if (remaining === null || remaining === undefined) return false;
  return remaining < threshold;
}

