// Error classifier — copy from L5 for capstone self-containment.
export function classifyError(httpStatus, body, headers = null) {
  if (httpStatus === 429) {
    const resetHeader = headers?.get('x-rate-limit-reset');
    const resetMs = resetHeader ? parseInt(resetHeader, 10) * 1000 : Date.now() + 60_000;
    const retryAfterMs = Math.max(resetMs - Date.now(), 1000);
    return { branch: 'RETRY_AFTER_RESET', message: `Rate limited (429). Wait ${Math.ceil(retryAfterMs / 1000)}s. DO NOT tight-retry.`, retryAfterMs };
  }
  if (httpStatus === 401) return { branch: 'FATAL', message: `Unauthenticated (401). Check token.` };
  if (httpStatus === 403) return { branch: 'CHANGE_AUTH_MODE', message: `Forbidden (403). Use user-context PKCE for writes (Principle 14).` };
  return { branch: 'UNKNOWN', message: `HTTP ${httpStatus}: ${JSON.stringify(body)}` };
}
export function isProblemJson(body) {
  if (!body || typeof body !== 'object') return false;
  if (typeof body.title !== 'string') return false;
  if (typeof body.status !== 'number') return false;
  if (Array.isArray(body.errors)) return false;
  return true;
}

