// PKCE utilities — self-contained copy for capstone isolation.
import { createHash, randomBytes } from 'node:crypto';
export const generateCodeVerifier = (l = 64) => randomBytes(Math.ceil(l * 3 / 4)).toString('base64url').slice(0, l);
export const deriveCodeChallenge = (v) => createHash('sha256').update(v, 'ascii').digest('base64url');
export function buildAuthorizationUrl({ clientId, redirectUri, scopes, state, codeChallenge }) {
  const url = new URL('https://twitter.com/i/oauth2/authorize');
  url.searchParams.set('response_type', 'code');
  url.searchParams.set('client_id', clientId);
  url.searchParams.set('redirect_uri', redirectUri);
  url.searchParams.set('scope', scopes.join(' '));
  url.searchParams.set('state', state);
  url.searchParams.set('code_challenge', codeChallenge);
  url.searchParams.set('code_challenge_method', 'S256');
  return url.toString();
}
export async function exchangeCodeForToken({ code, codeVerifier, redirectUri, clientId, clientSecret }) {
  const credentials = Buffer.from(`${clientId}:${clientSecret}`).toString('base64');
  const res = await fetch('https://api.x.com/2/oauth2/token', {
    method: 'POST',
    headers: { 'Authorization': `Basic ${credentials}`, 'Content-Type': 'application/x-www-form-urlencoded' },
    body: new URLSearchParams({ code, grant_type: 'authorization_code', redirect_uri: redirectUri, code_verifier: codeVerifier }),
  });
  const body = await res.json();
  if (!res.ok) throw new Error(`Token exchange: ${res.status} ${JSON.stringify(body)}`);
  return body;
}

