// TOS-safe write client — composes L3 write-client + L5 rate-limit guard.
import { randomUUID } from 'node:crypto';
import { parseRateLimitHeaders, isRateLimitLow, msUntilReset } from './backoff.mjs';

const BASE = 'https://api.x.com/2';

export function buildTestPostText() {
  const uuid = randomUUID();
  // Link-free (Principle 15: $0.015 not $0.20)
  return { text: `[automated API test] ${uuid}`, uuid };
}

async function xPost(accessToken, path, body) {
  const res = await fetch(`${BASE}${path}`, {
    method: 'POST',
    headers: { 'Authorization': `Bearer ${accessToken}`, 'Content-Type': 'application/json' },
    body: JSON.stringify(body),
  });
  const json = await res.json();
  const rl = parseRateLimitHeaders(res.headers);
  if (isRateLimitLow(rl.remaining)) console.warn(`[rate-limit] remaining ${rl.remaining} — LOW (Principle 5)`);
  if (!res.ok) throw new Error(`POST ${path} failed: ${res.status} ${JSON.stringify(json)}`);
  return { data: json.data, rateLimit: rl };
}

async function xGet(accessToken, path) {
  const res = await fetch(`${BASE}${path}`, {
    headers: { 'Authorization': `Bearer ${accessToken}`, 'Accept': 'application/json' },
  });
  const json = await res.json();
  const rl = parseRateLimitHeaders(res.headers);
  if (isRateLimitLow(rl.remaining)) console.warn(`[rate-limit] remaining ${rl.remaining} — LOW (Principle 5)`);
  if (!res.ok) throw new Error(`GET ${path} failed: ${res.status} ${JSON.stringify(json)}`);
  return { data: json.data, rateLimit: rl };
}

async function xDelete(accessToken, path) {
  const res = await fetch(`${BASE}${path}`, {
    method: 'DELETE',
    headers: { 'Authorization': `Bearer ${accessToken}` },
  });
  const json = await res.json();
  const rl = parseRateLimitHeaders(res.headers);
  if (!res.ok) throw new Error(`DELETE ${path} failed: ${res.status} ${JSON.stringify(json)}`);
  return { data: json.data, rateLimit: rl };
}

export async function createPost(accessToken, text) { return xPost(accessToken, '/tweets', { text }); }
export async function verifyPost(accessToken, tweetId) { return xGet(accessToken, `/tweets/${tweetId}`); }
export async function deletePost(accessToken, tweetId) { return xDelete(accessToken, `/tweets/${tweetId}`); }

export async function safePostRoundTrip(accessToken, transport = null) {
  const { text, uuid } = buildTestPostText();
  const t = transport ?? { createPost, verifyPost, deletePost };
  let created = null;
  try {
    created = await t.createPost(accessToken, text);
    const verified = await t.verifyPost(accessToken, created.data?.id ?? created.id);
    const deleted = await t.deletePost(accessToken, created.data?.id ?? created.id);
    const deletedFlag = deleted.data?.deleted ?? deleted.deleted;
    if (!deletedFlag) throw new Error(`DELETE returned deleted:false for post ${created.data?.id} — manual cleanup required`);
    return { created: created.data ?? created, verified: verified.data ?? verified, deleted: deleted.data ?? deleted, uuid };
  } catch (err) {
    if (created) {
      try { await t.deletePost(accessToken, created.data?.id ?? created.id); } catch {}
    }
    throw err;
  }
}

