/**
 * Capstone keyless tests — no credentials needed.
 *
 * Composes keyless tests from all prior levels into one suite.
 * Proves the entire logic of the capstone is correct before credentials exist.
 *
 * Tests:
 *   1. Unauth 401 → problem+json + no x-rate-limit-* (live, from L0)
 *   2. PKCE S256 derivation (deterministic, from L2)
 *   3. buildAuthorizationUrl produces correct PKCE URL (deterministic, from L2)
 *   4. safePostRoundTrip: stubbed happy path → {deleted:true} (from L3)
 *   5. safePostRoundTrip: mandatory-delete guard → throws on deleted:false (from L3)
 *   6. msUntilReset: synthetic 429 → correct wait time (from L5)
 *   7. isProblemJson: v2 → true, v1.1 → false (from L5)
 */

import { test } from 'node:test';
import assert from 'node:assert/strict';
import { createHash } from 'node:crypto';
import { deriveCodeChallenge, buildAuthorizationUrl } from '../lib/pkce.mjs';
import { safePostRoundTrip } from '../lib/write-client.mjs';
import { msUntilReset, parseRateLimitHeaders } from '../lib/backoff.mjs';
import { isProblemJson } from '../lib/error-handler.mjs';

// ─── 1. Unauth 401 (live) ─────────────────────────────────────────────────

test('Capstone L0 anchor: unauth GET /2/tweets/20 → 401 problem+json + no rate-limit headers', async () => {
  const res = await fetch('https://api.x.com/2/tweets/20');
  assert.strictEqual(res.status, 401);
  const ct = res.headers.get('content-type') ?? '';
  assert.ok(ct.includes('application/problem+json'));
  const body = await res.json();
  assert.ok(isProblemJson(body), 'Must be v2 problem+json envelope');
  const rl = parseRateLimitHeaders(res.headers);
  assert.strictEqual(rl.limit, null, 'No x-rate-limit-limit on unauth 401');
  assert.strictEqual(rl.remaining, null, 'No x-rate-limit-remaining on unauth 401');
});

// ─── 2. PKCE S256 (L2) ───────────────────────────────────────────────────

test('Capstone L2 anchor: PKCE S256 derivation matches RFC 7636', () => {
  const verifier = 'dBjftJeZ4CVP-mB92K27uhbUJU1p1r_wW1gFWFOEjXk';
  const expected = 'E9Melhoa2OwvFrEMTJguCHaoeK1t8URWbuGJSstw-cM';
  assert.strictEqual(deriveCodeChallenge(verifier), expected);
});

// ─── 3. Authorization URL (L2) ───────────────────────────────────────────

test('Capstone L2 anchor: buildAuthorizationUrl includes all required PKCE params including tweet.write', () => {
  const url = new URL(buildAuthorizationUrl({
    clientId: 'capstone-client',
    redirectUri: 'https://example.com/callback',
    scopes: ['tweet.read', 'users.read', 'tweet.write'],
    state: 'capstone-state',
    codeChallenge: 'capstone-challenge',
  }));
  assert.strictEqual(url.searchParams.get('code_challenge_method'), 'S256');
  assert.ok(url.searchParams.get('scope').includes('tweet.write'), 'Must include tweet.write');
  assert.ok(url.searchParams.get('scope').includes('users.read'), 'Must include users.read');
});

// ─── 4. safePostRoundTrip happy path (L3) ────────────────────────────────

test('Capstone L3 anchor: safePostRoundTrip stubbed happy path → deleted:true + UUID in text', async () => {
  const transport = {
    createPost: async (_t, text) => ({ data: { id: 'cap-001', text } }),
    verifyPost: async (_t, id) => ({ data: { id, text: '[verified]' } }),
    deletePost: async (_t, _id) => ({ data: { deleted: true } }),
  };
  const result = await safePostRoundTrip('stub-token', transport);
  assert.ok(result.deleted.deleted === true, 'deleted must be true');
  assert.ok(result.created.text.includes('[automated API test]'), 'text must have TOS marker');
  assert.ok(result.created.text.includes(result.uuid), 'text must include UUID');
  // Post text must be link-free
  assert.ok(!result.created.text.includes('http'), 'Post text must be link-free (Principle 15)');
});

// ─── 5. Mandatory-delete guard (L3) ──────────────────────────────────────

test('Capstone L3 anchor: mandatory-delete guard throws when deleted:false', async () => {
  const transport = {
    createPost: async (_t, text) => ({ data: { id: 'cap-002', text } }),
    verifyPost: async (_t, id) => ({ data: { id } }),
    deletePost: async (_t, _id) => ({ data: { deleted: false } }),
  };
  await assert.rejects(() => safePostRoundTrip('stub-token', transport), /deleted:false|manual cleanup/);
});

// ─── 6. msUntilReset (L5) ────────────────────────────────────────────────

test('Capstone L5 anchor: msUntilReset 60s in future → ~60000ms', () => {
  const now = Date.now();
  const resetUnix = Math.ceil((now + 60_000) / 1000);
  const wait = msUntilReset(resetUnix, now);
  assert.ok(wait >= 59_000 && wait <= 61_000, `Expected ~60000ms, got ${wait}ms`);
});

// ─── 7. isProblemJson v2/v1.1 (L5) ───────────────────────────────────────

test('Capstone L5 anchor: isProblemJson v2 → true; v1.1 → false (CRITICAL NEGATIVE)', () => {
  assert.strictEqual(isProblemJson({ title: 'Unauthorized', type: 'about:blank', status: 401, detail: 'Unauthorized' }), true);
  assert.strictEqual(isProblemJson({ errors: [{ code: 32, message: 'Could not authenticate you.' }] }), false,
    'v1.1 shape must return false — agents must not use body.errors[0].code for v2 errors');
});

