// Vite dev-server plugin: a real /api/chat proxy for the L9 capstone. The browser chat POSTs the
// conversation here; this middleware (Node, server-side — ANTHROPIC_API_KEY never reaches the
// browser) calls Anthropic with the built-in library's system prompt and re-emits the streamed
// OpenUI Lang as OpenAI-style SSE deltas, which @openuidev/react-headless's openAIAdapter() parses.
import type { Plugin, ViteDevServer } from "vite"
import type { IncomingMessage, ServerResponse } from "node:http"
import Anthropic from "@anthropic-ai/sdk"

const MODEL = "claude-sonnet-4-6"

type ChatMsg = { role: "user" | "assistant"; content: string }

function readJson(req: IncomingMessage): Promise<Record<string, unknown>> {
  return new Promise((resolve) => {
    let data = ""
    req.on("data", (c) => (data += c))
    req.on("end", () => {
      try {
        resolve(JSON.parse(data || "{}"))
      } catch {
        resolve({})
      }
    })
  })
}

function normalize(msgs: unknown): ChatMsg[] {
  const arr = Array.isArray(msgs) ? msgs : []
  return arr
    .map((m): ChatMsg | null => {
      const role = (m as { role?: string })?.role
      if (role !== "user" && role !== "assistant") return null
      const raw = (m as { content?: unknown }).content
      const content =
        typeof raw === "string"
          ? raw
          : Array.isArray(raw)
            ? raw.map((p) => (typeof p === "string" ? p : ((p as { text?: string })?.text ?? ""))).join("")
            : String(raw ?? "")
      return content.trim() ? { role, content } : null
    })
    .filter((m): m is ChatMsg => m !== null)
}

export function openuiChatPlugin(): Plugin {
  let promptCache: string | null = null
  return {
    name: "openui-chat-proxy",
    configureServer(server: ViteDevServer) {
      server.middlewares.use("/api/chat", async (req: IncomingMessage, res: ServerResponse) => {
        if (req.method !== "POST") {
          res.statusCode = 405
          res.end("Method Not Allowed")
          return
        }
        try {
          const body = await readJson(req)
          const messages = normalize((body as { messages?: unknown }).messages)
          if (!process.env.ANTHROPIC_API_KEY) {
            res.statusCode = 503
            res.end("ANTHROPIC_API_KEY not set")
            return
          }
          if (!promptCache) {
            // Vite SSR module load handles the package's CSS side-effects (no-op in Node).
            const mod = (await server.ssrLoadModule("@openuidev/react-ui/genui-lib")) as {
              openuiLibrary: { prompt: (o: unknown) => string }
              openuiPromptOptions: unknown
            }
            promptCache = mod.openuiLibrary.prompt(mod.openuiPromptOptions)
          }
          res.setHeader("Content-Type", "text/event-stream")
          res.setHeader("Cache-Control", "no-cache")
          res.setHeader("Connection", "keep-alive")

          const client = new Anthropic()
          const stream = client.messages.stream({
            model: MODEL,
            max_tokens: 1600,
            system: promptCache,
            messages: messages.length ? messages : [{ role: "user", content: "Say hello." }],
          })
          stream.on("text", (t: string) => {
            res.write(`data: ${JSON.stringify({ choices: [{ delta: { content: t } }] })}\n\n`)
          })
          await stream.finalMessage()
          res.write("data: [DONE]\n\n")
          res.end()
        } catch (e) {
          try {
            res.statusCode = 500
            res.end(String(e))
          } catch {
            /* already sent */
          }
        }
      })
    },
  }
}

