// L9 — CAPSTONE: a full generative-UI chat. Composes everything: react-headless manages chat state
// (ChatProvider + useThread); a user message streams through the Vite /api/chat proxy to real Claude,
// which authors OpenUI Lang; each assistant bubble renders that OpenUI Lang as live React via
// <Renderer isStreaming> — so charts/tables/cards appear and fill in progressively (L2/L4/L6 concepts).
import * as React from "react"
import {
  ChatProvider,
  fetchLLM,
  openAIAdapter,
  openAIMessageFormat,
  useThread,
} from "@openuidev/react-headless"
import { Renderer } from "@openuidev/react-lang"
import { openuiLibrary } from "../lib/genui"

const llm = fetchLLM({
  url: "/api/chat",
  streamAdapter: openAIAdapter(),
  messageFormat: openAIMessageFormat,
})

function Bubble({ role, content, isStreaming }: { role: string; content: string; isStreaming: boolean }) {
  const isUser = role === "user"
  return (
    <div
      data-testid={`msg-${role}`}
      style={{ display: "flex", justifyContent: isUser ? "flex-end" : "flex-start", margin: "12px 0" }}
    >
      <div
        style={{
          maxWidth: isUser ? "70%" : "94%",
          background: isUser ? "#6366f1" : "#ffffff",
          color: isUser ? "#fff" : "inherit",
          border: isUser ? "none" : "1px solid #e6e8ec",
          borderRadius: 16,
          padding: isUser ? "10px 16px" : "16px 18px",
          boxShadow: isUser ? "none" : "0 8px 24px rgba(16,24,40,0.06)",
          width: isUser ? "auto" : "100%",
        }}
      >
        {isUser ? content : <Renderer library={openuiLibrary} response={content} isStreaming={isStreaming} />}
      </div>
    </div>
  )
}

function ChatUI() {
  const { messages, isRunning, processMessage } = useThread()
  const [input, setInput] = React.useState(
    "Show me Q3 revenue by region as a bar chart, plus a summary card highlighting the top region.",
  )
  const lastId = messages.length ? messages[messages.length - 1].id : null
  return (
    <div style={{ maxWidth: 820 }}>
      <span data-testid="running" data-running={isRunning ? "1" : "0"} style={{ display: "none" }} />
      <div data-testid="messages" style={{ minHeight: 120, marginBottom: 16 }}>
        {messages.map((m) => (
          <Bubble
            key={m.id}
            role={m.role}
            content={String((m as { content?: unknown }).content ?? "")}
            isStreaming={isRunning && m.role !== "user" && m.id === lastId}
          />
        ))}
      </div>
      <form
        onSubmit={(e) => {
          e.preventDefault()
          if (!input.trim() || isRunning) return
          processMessage({ role: "user", content: input })
        }}
        style={{ display: "flex", gap: 8 }}
      >
        <input
          data-testid="chat-input"
          value={input}
          onChange={(e) => setInput(e.target.value)}
          placeholder="Ask for a dashboard, table, form…"
          style={{ flex: 1, padding: "12px 14px", borderRadius: 12, border: "1px solid #d0d5dd", fontSize: 14 }}
        />
        <button
          data-testid="send"
          type="submit"
          disabled={isRunning}
          style={{ padding: "12px 20px", borderRadius: 12, border: "none", background: "#6366f1", color: "#fff", fontWeight: 600 }}
        >
          Send
        </button>
      </form>
    </div>
  )
}

export function L9Chat() {
  return (
    <div className="poc-stage" data-testid="l9-stage">
      <p className="poc-title">L9 · capstone · generative-UI chat</p>
      <ChatProvider llm={llm}>
        <ChatUI />
      </ChatProvider>
    </div>
  )
}

