### source/assert.mjs
```mjs
#!/usr/bin/env node
/**
 * L-capstone assertion script — Au Advisor custom agent driven over HTTP.
 * Usage: node assert.mjs [--port 3888]
 * Exit 0 = all assertions pass (GREEN)
 * Exit 1 = assertion failure (RED / expected pre-impl failure)
 *
 * REUSES: session-drive pattern from L4 assert.mjs
 *
 * KEY ASSERTIONS (capstone chain):
 *  A1: session.started with modelId  → proves gateway model call (L4 pattern)
 *  A2: actions.requested with get_travel_weather → proves custom tool was recognized
 *  A3: tool called with "Seoul" in city field  → proves tool contract (L3 pattern)
 *  A4: action.result with temperature_c field  → proves custom tool executed (Open-Meteo live)
 *  A5: message.completed with weather-grounded reply → proves LLM synthesized real data
 *  A6 (regression): session.waiting / session.completed terminal event
 */

const PORT = (() => {
  const idx = process.argv.indexOf("--port");
  return idx !== -1 ? Number(process.argv[idx + 1]) : 3888;
})();

const BASE = `http://127.0.0.1:${PORT}`;
const STREAM_TIMEOUT_MS = 120_000; // 2min — real model + Open-Meteo call

function fail(msg, detail) {
  console.error(`\n[FAIL] ${msg}`);
  if (detail) console.error("       Detail:", detail);
  process.exit(1);
}

function pass(msg) {
  console.log(`[PASS] ${msg}`);
}

async function readNdjsonStream(resp) {
  const events = [];
  const rawLines = [];
  const reader = resp.body.getReader();
  const decoder = new TextDecoder();
  let buf = "";

  const TERMINAL_TYPES = new Set([
    "session.waiting",
    "session.completed",
    "session.failed",
    "turn.failed",
  ]);

  const timeoutId = setTimeout(() => {
    reader.cancel("stream timeout").catch(() => {});
  }, STREAM_TIMEOUT_MS);

  try {
    while (true) {
      let result;
      try {
        result = await reader.read();
      } catch {
        break;
      }
      const { done, value } = result;
      if (done) break;
      buf += decoder.decode(value, { stream: true });
      const lines = buf.split("\n");
      buf = lines.pop();
      for (const line of lines) {
        const trimmed = line.trim();
        if (!trimmed) continue;
        rawLines.push(trimmed);
        try {
          const ev = JSON.parse(trimmed);
          events.push(ev);
          if (TERMINAL_TYPES.has(ev.type)) {
            reader.cancel("terminal event received").catch(() => {});
            if (buf.trim()) {
              rawLines.push(buf.trim());
              try { events.push(JSON.parse(buf.trim())); } catch {}
            }
            clearTimeout(timeoutId);
            return { events, rawLines };
          }
        } catch {
          console.warn("  [WARN] Non-JSON line:", trimmed);
        }
      }
    }
  } finally {
    clearTimeout(timeoutId);
  }

  if (buf.trim()) {
    rawLines.push(buf.trim());
    try { events.push(JSON.parse(buf.trim())); } catch {}
  }
  return { events, rawLines };
}

async function run() {
  // --- Step 1: Create session ---
  // The prompt forces the get_travel_weather tool to be called.
  const PROMPT = "I am travelling to Seoul next week. What should I pack based on the current weather?";
  console.log(`\n=== POST ${BASE}/eve/v1/session ===`);
  console.log(`Prompt: "${PROMPT}"`);
  let sessionResp;
  try {
    sessionResp = await fetch(`${BASE}/eve/v1/session`, {
      method: "POST",
      headers: { "content-type": "application/json" },
      body: JSON.stringify({ message: PROMPT }),
    });
  } catch (e) {
    fail("Could not connect to eve server", e.message);
  }

  if (!sessionResp.ok) {
    const body = await sessionResp.text();
    fail(`Session creation failed: HTTP ${sessionResp.status}`, body);
  }

  const sessionBody = await sessionResp.json();
  console.log("Session response body:", JSON.stringify(sessionBody, null, 2));

  const sessionId = sessionResp.headers.get("x-eve-session-id") || sessionBody.sessionId;
  const continuationToken = sessionBody.continuationToken;

  if (!sessionId) fail("Missing sessionId (neither x-eve-session-id header nor sessionBody.sessionId)");
  if (!continuationToken) fail("Missing continuationToken in response body");

  pass(`Session created: sessionId=${sessionId}`);
  pass(`Continuation token present: ${continuationToken.slice(0, 20)}...`);

  // --- Step 2: Stream session ---
  console.log(`\n=== GET ${BASE}/eve/v1/session/${sessionId}/stream ===`);
  let streamResp;
  try {
    streamResp = await fetch(`${BASE}/eve/v1/session/${sessionId}/stream`);
  } catch (e) {
    fail("Could not connect to stream endpoint", e.message);
  }

  if (!streamResp.ok) {
    const body = await streamResp.text();
    fail(`Stream failed: HTTP ${streamResp.status}`, body);
  }

  const { events, rawLines } = await readNdjsonStream(streamResp);

  console.log("\n--- Raw NDJSON stream ---");
  for (const l of rawLines) console.log(l);
  console.log("--- End stream ---\n");

  // --- Assertions ---

  // A1: session.started event with modelId (proves real gateway model call — L4 lesson)
  const sessionStarted = events.find(e => e.type === "session.started");
  if (!sessionStarted) {
    fail(
      "ASSERTION A1 FAILED: no session.started event",
      `Event types seen: ${events.map(e => e.type).join(", ")}`
    );
  }
  const modelId = sessionStarted.data?.runtime?.modelId;
  if (!modelId) {
    fail("ASSERTION A1b FAILED: session.started has no runtime.modelId", JSON.stringify(sessionStarted));
  }
  pass(`A1: session.started with modelId=${modelId}`);

  // A2: actions.requested event with get_travel_weather tool call (proves custom tool installed from custom registry)
  const actionsRequested = events.find(
    e =>
      e.type === "actions.requested" &&
      Array.isArray(e.data?.actions) &&
      e.data.actions.some(a => a.toolName === "get_travel_weather")
  );

  if (!actionsRequested) {
    fail(
      "ASSERTION A2 FAILED: no actions.requested event containing get_travel_weather tool call",
      `Event types seen: ${events.map(e => e.type).join(", ")}`
    );
  }
  const travelAction = actionsRequested.data.actions.find(a => a.toolName === "get_travel_weather");
  console.log("get_travel_weather action call:", JSON.stringify(travelAction, null, 2));
  pass("A2: actions.requested event with get_travel_weather tool call found");

  // A3: get_travel_weather called with Seoul in city (proves tool contract — L3 lesson)
  const cityArg = travelAction?.input?.city || travelAction?.input?.location;
  if (!cityArg || !cityArg.toLowerCase().includes("seoul")) {
    fail(
      `ASSERTION A3 FAILED: get_travel_weather not called with Seoul. Got city=${cityArg}`,
      JSON.stringify(travelAction)
    );
  }
  pass(`A3: get_travel_weather called with city="${cityArg}"`);

  // A4: action.result with temperature_c field (proves custom tool executed and Open-Meteo responded)
  const actionResult = events.find(e => e.type === "action.result");
  if (!actionResult) {
    fail(
      "ASSERTION A4 FAILED: no action.result event found",
      `Event types seen: ${events.map(e => e.type).join(", ")}`
    );
  }
  const resultOutput = actionResult.data?.result?.output;
  const hasWeatherShape = (
    resultOutput != null &&
    typeof resultOutput === "object" &&
    !resultOutput.error &&
    typeof resultOutput.temperature_c === "number"
  );
  if (!hasWeatherShape) {
    fail(
      "ASSERTION A4b FAILED: action.result output missing temperature_c (custom tool schema)",
      JSON.stringify(resultOutput)
    );
  }
  pass(`A4: action.result has temperature_c=${resultOutput.temperature_c}°C (Live Open-Meteo data for ${resultOutput.city || cityArg})`);

  // A5: message.completed with weather-grounded packing advice (proves LLM synthesized real data)
  const messageCompleted = events.find(e => e.type === "message.completed");
  if (!messageCompleted) {
    fail(
      "ASSERTION A5 FAILED: no message.completed event",
      `Event types seen: ${events.map(e => e.type).join(", ")}`
    );
  }
  const reply = messageCompleted.data?.message || "";
  const replyStr = typeof reply === "string" ? reply : JSON.stringify(reply);
  const mentionsWeatherOrLocation =
    replyStr.toLowerCase().includes("seoul") ||
    replyStr.toLowerCase().includes("temperature") ||
    replyStr.toLowerCase().includes("°") ||
    replyStr.toLowerCase().includes("celsius") ||
    replyStr.toLowerCase().includes("pack") ||
    replyStr.toLowerCase().includes("weather");

  if (!mentionsWeatherOrLocation) {
    fail(
      `ASSERTION A5 FAILED: message.completed reply doesn't mention weather/packing/Seoul. Got: ${replyStr.slice(0, 300)}`
    );
  }
  pass(`A5: message.completed reply is weather-grounded packing advice: "${replyStr.slice(0, 150)}..."`);

  // A6 (regression): terminal session event present (proves session ran to completion)
  const sessionTerminal = events.find(
    e => e.type === "session.waiting" || e.type === "session.completed"
  );
  if (!sessionTerminal) {
    fail(
      "ASSERTION A6 (REGRESSION) FAILED: no session.waiting or session.completed event",
      `Event types seen: ${events.map(e => e.type).join(", ")}`
    );
  }
  pass(`A6 (REGRESSION): terminal session event present (${sessionTerminal.type})`);

  console.log("\n=== ALL ASSERTIONS PASSED ===");
  console.log(`Session ID: ${sessionId}`);
  console.log(`Continuation token: ${continuationToken.slice(0, 30)}...`);
  console.log(`Model ID (from gateway): ${modelId}`);
  console.log(`Tool: get_travel_weather → city="${cityArg}" → temperature=${resultOutput.temperature_c}°C`);
  console.log(`Model reply: "${replyStr.slice(0, 400)}"`);
}

run().catch(err => {
  console.error("[UNHANDLED ERROR]", err);
  process.exit(1);
});

