/**
 * Task store — external vanilla store using useSyncExternalStore.
 * Stable snapshot reference (L14 pattern): only a new object is created on mutation.
 */
import { useSyncExternalStore } from 'react'

export interface Task {
  id: string
  title: string
  done: boolean
}

type Listener = () => void

let tasks: Task[] = []
let cachedSnapshot: Task[] = tasks
let listeners: Set<Listener> = new Set()

function getSnapshot(): Task[] {
  return cachedSnapshot
}

function getServerSnapshot(): Task[] {
  return cachedSnapshot
}

function setTasks(next: Task[]): void {
  tasks = next
  cachedSnapshot = tasks
  listeners.forEach((l) => l())
}

function subscribe(listener: Listener): () => void {
  listeners.add(listener)
  return () => listeners.delete(listener)
}

export const taskStore = {
  getSnapshot,
  getServerSnapshot,
  setTasks,
  subscribe,
}

export function resetStore(initial: Task[] = []): void {
  tasks = initial
  cachedSnapshot = initial
  listeners = new Set()
}

export function useTaskStore(): Task[] {
  return useSyncExternalStore(
    taskStore.subscribe,
    taskStore.getSnapshot,
    taskStore.getServerSnapshot,
  )
}

