// Secure Document Assistant — capstone for the Auth0-for-AI-Agents degree.
//
// Combines:
//   L1  ReBAC model           -> document{owner,editor,viewer} relations in OpenFGA
//   L2  groups/relations      -> group{member}, group#member as a viewer/editor subject
//   L3  FGA-gated RAG         -> retrieval is filtered by a batchCheck(viewer) per user
//   L5  failure + audit       -> sensitive action gated on can_share + a per-tool audit log
//
// Live services (NO MOCKS):
//   - OpenFGA engine  : self-hosted, http://localhost:8195  (keyless)
//   - Anthropic       : claude-haiku-4-5-20251001 with tool use (ANTHROPIC_API_KEY)
//
// Production framing: with a real Auth0 / FGA tenant the same model + checks run against
// `api.<tenant>.auth0.com` instead of localhost, and the human-gate on share_document
// (the can_share denial) becomes a CIBA async-approval push — see surprises.md.

import { OpenFgaClient } from "@openfga/sdk";
import Anthropic from "@anthropic-ai/sdk";

export const FGA_API_URL = process.env.FGA_API_URL || "http://localhost:8195";
export const MODEL = "claude-haiku-4-5-20251001";

// ---------------------------------------------------------------------------
// FGA authorization model (schema 1.1)
// document:
//   owner  : [user]
//   editor : (this | owner)                        subjects: user, group#member
//   viewer : (this | editor)                       subjects: user, group#member
//   can_share : computedUserset(owner)             only owners may share
// group:
//   member : [user]
// ---------------------------------------------------------------------------
export const AUTH_MODEL = {
  schema_version: "1.1",
  type_definitions: [
    { type: "user" },
    {
      type: "group",
      relations: { member: { this: {} } },
      metadata: {
        relations: {
          member: { directly_related_user_types: [{ type: "user" }] },
        },
      },
    },
    {
      type: "document",
      relations: {
        owner: { this: {} },
        editor: {
          union: {
            child: [
              { this: {} },
              { computedUserset: { object: "", relation: "owner" } },
            ],
          },
        },
        viewer: {
          union: {
            child: [
              { this: {} },
              { computedUserset: { object: "", relation: "editor" } },
            ],
          },
        },
        // Only an owner may share. computedUserset over the local `owner` relation.
        can_share: { computedUserset: { object: "", relation: "owner" } },
      },
      metadata: {
        relations: {
          owner: { directly_related_user_types: [{ type: "user" }] },
          editor: {
            directly_related_user_types: [
              { type: "user" },
              { type: "group", relation: "member" },
            ],
          },
          viewer: {
            directly_related_user_types: [
              { type: "user" },
              { type: "group", relation: "member" },
            ],
          },
        },
      },
    },
  ],
};

// ---------------------------------------------------------------------------
// Corpus: ~6 docs. One is exec-only and carries a sentinel secret.
// ---------------------------------------------------------------------------
export const SENTINEL = "PROJECT-NIGHTJAR";

export const CORPUS = [
  {
    id: "document:roadmap",
    title: "Engineering Roadmap Q3",
    body: "Q3 engineering roadmap: ship the auth gateway, migrate the search index, and harden the rate limiter. Owner: alice.",
  },
  {
    id: "document:onboarding",
    title: "New Hire Onboarding",
    body: "Onboarding checklist for new engineers: laptop setup, VPN, code review norms, and the on-call rotation.",
  },
  {
    id: "document:incident-2026-05",
    title: "Incident Review May 2026",
    body: "Postmortem for the May 2026 search outage. Root cause was a missing connection-pool limit. Action items assigned.",
  },
  {
    id: "document:style-guide",
    title: "API Style Guide",
