  { user: "user:alice", relation: "owner", object: "document:roadmap" },
  { user: "user:alice", relation: "owner", object: "document:perf-notes" },

  // eng group can view the non-confidential corpus
  { user: "group:eng#member", relation: "viewer", object: "document:onboarding" },
  { user: "group:eng#member", relation: "viewer", object: "document:incident-2026-05" },
  { user: "group:eng#member", relation: "viewer", object: "document:style-guide" },
  { user: "group:eng#member", relation: "viewer", object: "document:roadmap" },
  { user: "group:eng#member", relation: "viewer", object: "document:perf-notes" },

  // ONLY exec can view the acquisition memo (the sentinel doc)
  { user: "group:exec#member", relation: "viewer", object: "document:acquisition" },
];

// ---------------------------------------------------------------------------
// FGA setup: create a fresh store + model, seed tuples. Returns a configured client.
// ---------------------------------------------------------------------------
export async function setupFga() {
  const bootstrap = new OpenFgaClient({ apiUrl: FGA_API_URL });
  const { id: storeId } = await bootstrap.createStore({
    name: "secure-document-assistant-capstone",
  });

  const client = new OpenFgaClient({ apiUrl: FGA_API_URL, storeId });
  const { authorization_model_id: modelId } =
    await client.writeAuthorizationModel(AUTH_MODEL);
  client.authorizationModelId = modelId;

  await client.write({ writes: SEED_TUPLES });

  return { client, storeId, modelId };
}

// ---------------------------------------------------------------------------
// Audit log: every tool call appends {timestamp, user, tool, object, fga_decision, latency_ms}.
// No secrets (never the doc body / sentinel) — only ids + decisions.
// ---------------------------------------------------------------------------
export function makeAuditLog() {
  const entries = [];
  return {
    entries,
    record(e) {
      const row = {
        timestamp: new Date().toISOString(),
        user: e.user,
        tool: e.tool,
        object: e.object ?? null,
        fga_decision: e.fga_decision, // boolean (allowed)
        latency_ms: e.latency_ms,
      };
      entries.push(row);
      return row;
    },
  };
}

// ---------------------------------------------------------------------------
// Tool implementations — each one performs a REAL FGA call and audits it.
// ---------------------------------------------------------------------------

// search_docs: FGA-gated retrieval (L3). batchCheck viewer for the current user across
// the whole corpus; only authorized docs become context. Returns sanitized docs.
export async function searchDocs({ fga, audit, user, query, gateShare }) {
  const t0 = performance.now();
  const { result } = await fga.batchCheck({
    checks: CORPUS.map((d) => ({
      user,
      relation: "viewer",
      object: d.id,
      correlationId: d.id.replace(/[^a-zA-Z0-9]/g, ""),
    })),
  });
  const latency = Math.round(performance.now() - t0);

  const allowedIds = result.filter((r) => r.allowed).map((r) => r.request.object);
  const allowedSet = new Set(allowedIds);

  // naive lexical match over authorized docs only
  const q = (query || "").toLowerCase();
  const hits = CORPUS.filter(
    (d) =>
      allowedSet.has(d.id) &&
      (q === "" ||
        d.title.toLowerCase().includes(q) ||
        d.body.toLowerCase().includes(q) ||
        q.split(/\s+/).some((w) => w.length > 2 && d.body.toLowerCase().includes(w)))
  );

  audit.record({
    user,
    tool: "search_docs",
    object: `[${allowedIds.length}/${CORPUS.length} authorized]`,
    fga_decision: allowedIds.length > 0,
    latency_ms: latency,
  });

  return {
    authorizedDocIds: allowedIds,
    deniedDocIds: CORPUS.map((d) => d.id).filter((id) => !allowedSet.has(id)),
    documents: hits.map((d) => ({ id: d.id, title: d.title, body: d.body })),
  };
}

// share_document: SENSITIVE action gated on can_share (L5). If gateShare is false (the
// RED build) the gate is skipped and any user can share — the regression we are catching.
export async function shareDocument({ fga, audit, user, documentId, targetUser, gateShare }) {
  const t0 = performance.now();
  let allowed = true; // RED default: ungated

  if (gateShare) {
    const res = await fga.check({
      user,
      relation: "can_share",
      object: documentId,
    });
    allowed = res.allowed === true;
  }
  const latency = Math.round(performance.now() - t0);

  audit.record({
    user,
    tool: "share_document",
    object: documentId,
    fga_decision: allowed,
    latency_ms: latency,
  });

  if (!allowed) {
    return {
      shared: false,
      reason: `denied: ${user} is not an owner of ${documentId} and may not share it`,
    };
  }

  // Allowed: write a new viewer tuple granting targetUser access.
  await fga.write({
    writes: [{ user: targetUser, relation: "viewer", object: documentId }],
  });

  return {
    shared: true,
    documentId,
    targetUser,
    note: `granted viewer on ${documentId} to ${targetUser}`,
  };
}

