const ADMIN = process.env.GATEWAY_ADMIN_KEY || 'admin-secret';
const SMALL = () => ({ model: MODEL, messages: [{ role: 'user', content: 'Say OK' }], max_tokens: 8, temperature: 0 });
function assertNoSecretLeak(haystack, where) {
  const key = process.env.FIREWORKS_API_KEY;
  assert.ok(typeof key === 'string' && /^fw_/.test(key) && key.length > 8, 'precondition: FIREWORKS_API_KEY must be a non-empty fw_ key');
  for (const f of [key, key.slice(3), Buffer.from(key).toString('base64'), encodeURIComponent(key), `Bearer ${key}`]) {
    assert.ok(!haystack.includes(f), `upstream key leak in ${where}`);
  }
}

test('L5 capstone: multi-tenant gateway over a real socket -> live Fireworks; cap enforced on one tenant; report reconciles; no leak', async () => {
  const store = new Store(':memory:'); const logs = [];
  const gw = createGateway({ store, adminKey: ADMIN, log: (l) => logs.push(l) });
  const server = await serve(gw, 0);
  const base = `http://localhost:${server.address().port}`;
  try {
    const admin = async (p, b) => (await fetch(base + p, { method: 'POST', headers: { 'x-admin-key': ADMIN, 'content-type': 'application/json' }, body: JSON.stringify(b) })).json();
    const t1 = await admin('/v1/admin/tenants', { id: 'team-a', name: 'Team A' });
    const t2 = await admin('/v1/admin/tenants', { id: 'team-b', name: 'Team B', tokenLimit: 5 });
    assert.ok(t1.key && t2.key, 'admin issued tenant keys over HTTP (shown once)');
    const call = (k) => fetch(base + '/v1/chat/completions', { method: 'POST', headers: { authorization: `Bearer ${k}`, 'content-type': 'application/json' }, body: JSON.stringify(SMALL()) });

    // team-a: real traffic
