// pricing.mjs — Fireworks serverless price table + integer cost model.
//
// LIVE-VERIFIED rates (USD per 1,000,000 tokens), captured 2026-06-21 from
// https://docs.fireworks.ai/serverless/pricing :
//   gpt-oss-120b : input $0.15 / cached-input $0.015 / output $0.60
//   gpt-oss-20b  : input $0.07 / cached-input $0.035 / output $0.30
//   glm-5p2      : input $1.40 / cached-input $0.26  / output $4.40
//
// We store rates as INTEGER nano-USD per token (1 USD = 1e9 nano-USD) so cost
// arithmetic never touches floating point (no drift across millions of tokens).
//   nano_per_token = usd_per_1M * 1000   (e.g. $0.60/1M -> 600 nano/token)

/** @typedef {{input:number, cachedInput:number, output:number}} Rate  (nano-USD/token) */

/** @type {Record<string, Rate>} */
export const PRICE_TABLE = {
  'accounts/fireworks/models/gpt-oss-120b': { input: 150, cachedInput: 15, output: 600 },
  'accounts/fireworks/models/gpt-oss-20b': { input: 70, cachedInput: 35, output: 300 },
  'accounts/fireworks/models/glm-5p2': { input: 1400, cachedInput: 260, output: 4400 },
};

// Parameter-band REFERENCE rates for catalog models not individually priced
// (USD/1M, applied uniformly to input+output; no separate cached rate).
// Source: same docs page, "Parameter-Based Pricing" table.
// NOTE: these are REFERENCE rates only — they are NOT auto-applied by costNano.
// A cost-attribution gateway must know the exact price of every model it serves,
// so the gateway rejects (400) any model not in PRICE_TABLE rather than guessing
// a band. To add a model, put its exact rate in PRICE_TABLE (operators map these
// bands manually when a model isn't individually listed).
export const BAND_FALLBACK_NANO_PER_TOKEN = {
  lt4b: 100, // <4B  -> $0.10/1M
  '4to16b': 200, // 4-16B -> $0.20/1M
  gt16b: 900, // >16B  -> $0.90/1M
  moeLe56b: 500, // MoE <=56B  -> $0.50/1M
  moe56to176b: 1200, // MoE 56.1-176B -> $1.20/1M
};

/** True if the gateway can price (and therefore meter + attribute cost for) a model. */
export function hasPrice(model) {
  return Object.prototype.hasOwnProperty.call(PRICE_TABLE, model);
}

/**
 * Compute the cost of one inference call in integer nano-USD from the REAL
 * Fireworks `usage` object. Honors `prompt_tokens_details.cached_tokens`:
 * cached prompt tokens are billed at the cheaper cached-input rate.
 *
 * @param {string} model  upstream model id (e.g. accounts/fireworks/models/glm-5p2)
 * @param {{prompt_tokens:number, completion_tokens:number, prompt_tokens_details?:{cached_tokens?:number}}} usage
 * @returns {number} cost in nano-USD (integer)
 */
export function costNano(model, usage) {
  const rate = PRICE_TABLE[model];
  if (!rate) {
    throw new Error(`no price for model ${model}; add it to PRICE_TABLE or map to a band`);
  }
  const prompt = usage.prompt_tokens ?? 0;
  const completion = usage.completion_tokens ?? 0;
  const cached = usage.prompt_tokens_details?.cached_tokens ?? 0;
  const billablePrompt = Math.max(0, prompt - cached);
  return billablePrompt * rate.input + cached * rate.cachedInput + completion * rate.output;
}

/** Format integer nano-USD as a USD string (6 decimal places). */
export function nanoToUsd(nano) {
  return (nano / 1e9).toFixed(6);
}

