// store.mjs — persistence layer (node:sqlite, zero external deps).
// Production: a file-backed SQLite DB. Tests: ':memory:' for a clean DB per test.
//
// Security property: tenant API keys are stored as SHA-256 HASHES, never plaintext.
// The plaintext key is shown to the operator exactly once (at issue/rotate time).

import { DatabaseSync } from 'node:sqlite';
import { createHash, randomBytes } from 'node:crypto';

/** SHA-256 hex of a tenant key. The only representation we persist. */
export function hashKey(key) {
  return createHash('sha256').update(key).digest('hex');
}

/** Generate a fresh opaque tenant key: `sk-tenant-<32 hex>`. */
export function generateTenantKey() {
  return `sk-tenant-${randomBytes(16).toString('hex')}`;
}

export class Store {
  /** @param {string} [path] sqlite path; ':memory:' (default) for an ephemeral test DB */
  constructor(path = ':memory:') {
    this.db = new DatabaseSync(path);
    this.db.exec(`
      CREATE TABLE IF NOT EXISTS tenants (
        id           TEXT PRIMARY KEY,
        name         TEXT NOT NULL,
        key_hash     TEXT UNIQUE NOT NULL,
        status       TEXT NOT NULL DEFAULT 'active',   -- 'active' | 'revoked'
        token_limit  INTEGER,            -- NULL = unlimited (total tokens)
        usd_limit_nano INTEGER,          -- NULL = unlimited (spend cap, nano-USD)
        rpm_limit    INTEGER,            -- NULL = unlimited (requests/min)
        created_at   TEXT NOT NULL,
        revoked_at   TEXT
      );
      CREATE TABLE IF NOT EXISTS usage_events (
        id               INTEGER PRIMARY KEY AUTOINCREMENT,
        tenant_id        TEXT NOT NULL,
        ts               TEXT NOT NULL,
        model            TEXT NOT NULL,
        prompt_tokens    INTEGER NOT NULL,
        completion_tokens INTEGER NOT NULL,
        cached_tokens    INTEGER NOT NULL DEFAULT 0,
        total_tokens     INTEGER NOT NULL,
        cost_nano        INTEGER NOT NULL,
        fireworks_id     TEXT
      );
      CREATE INDEX IF NOT EXISTS idx_usage_tenant ON usage_events(tenant_id);
    `);
  }

  /**
   * Create a tenant. Returns { id, key } where `key` is the PLAINTEXT key — show
   * it to the operator once; only its hash is stored.
   * @param {{id:string, name:string, tokenLimit?:number|null, usdLimitNano?:number|null, rpmLimit?:number|null, nowIso:string}} opts
   */
  createTenant({ id, name, tokenLimit = null, usdLimitNano = null, rpmLimit = null, nowIso }) {
    const key = generateTenantKey();
    this.db
      .prepare(
        `INSERT INTO tenants (id, name, key_hash, status, token_limit, usd_limit_nano, rpm_limit, created_at)
         VALUES (?, ?, ?, 'active', ?, ?, ?, ?)`,
      )
      .run(id, name, hashKey(key), tokenLimit, usdLimitNano, rpmLimit, nowIso);
    return { id, key };
  }

  /** Look up a tenant by presented plaintext key (hash compare). Returns row or undefined. */
  findTenantByKey(key) {
    return this.db.prepare(`SELECT * FROM tenants WHERE key_hash = ?`).get(hashKey(key));
  }

  getTenant(id) {
    return this.db.prepare(`SELECT * FROM tenants WHERE id = ?`).get(id);
  }

  /** Rotate: install a new key hash for an existing tenant. Old key stops working. Returns new plaintext key. */
  rotateKey(id) {
    const key = generateTenantKey();
    const info = this.db.prepare(`UPDATE tenants SET key_hash = ? WHERE id = ?`).run(hashKey(key), id);
    if (info.changes === 0) throw new Error(`tenant ${id} not found`);
    return key;
  }

  /** Revoke: mark a tenant revoked (its key -> 401). */
  revokeTenant(id, nowIso) {
    const info = this.db
      .prepare(`UPDATE tenants SET status = 'revoked', revoked_at = ? WHERE id = ?`)
      .run(nowIso, id);
    if (info.changes === 0) throw new Error(`tenant ${id} not found`);
  }

  /**
   * Record one metered call from the REAL Fireworks response usage.
   * @param {{tenantId:string, nowIso:string, model:string, usage:object, costNano:number, fireworksId?:string}} ev
   */
  recordUsage({ tenantId, nowIso, model, usage, costNano, fireworksId }) {
    const cached = usage.prompt_tokens_details?.cached_tokens ?? 0;
    this.db
      .prepare(
        `INSERT INTO usage_events
           (tenant_id, ts, model, prompt_tokens, completion_tokens, cached_tokens, total_tokens, cost_nano, fireworks_id)
         VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)`,
      )
      .run(
        tenantId,
        nowIso,
        model,
        usage.prompt_tokens ?? 0,
        usage.completion_tokens ?? 0,
        cached,
        usage.total_tokens ?? (usage.prompt_tokens ?? 0) + (usage.completion_tokens ?? 0),
        costNano,
        fireworksId ?? null,
      );
  }

  /** Aggregate usage for one tenant (token totals + cost + call count). */
  getUsage(tenantId) {
    const agg = this.db
      .prepare(
        `SELECT
           COUNT(*)                       AS calls,
           COALESCE(SUM(prompt_tokens),0)     AS prompt_tokens,
           COALESCE(SUM(completion_tokens),0) AS completion_tokens,
           COALESCE(SUM(cached_tokens),0)     AS cached_tokens,
           COALESCE(SUM(total_tokens),0)      AS total_tokens,
           COALESCE(SUM(cost_nano),0)         AS cost_nano
         FROM usage_events WHERE tenant_id = ?`,
      )
      .get(tenantId);
    return agg;
  }

  /** Per-model usage breakdown for a tenant (for cost attribution / chargeback). */
  getUsageByModel(tenantId) {
    return this.db
      .prepare(
        `SELECT model,
                COUNT(*) AS calls,
                COALESCE(SUM(prompt_tokens),0)     AS prompt_tokens,
                COALESCE(SUM(completion_tokens),0) AS completion_tokens,
                COALESCE(SUM(cached_tokens),0)     AS cached_tokens,
                COALESCE(SUM(cost_nano),0)         AS cost_nano
         FROM usage_events WHERE tenant_id = ? GROUP BY model`,
      )
      .all(tenantId);
  }

  close() {
    this.db.close();
  }
}

