// ---------------------------------------------------------------------------
// 4. Eden Treaty + raw handle: typed CRUD lifecycle
// ---------------------------------------------------------------------------

describe('Eden Treaty: typed CRUD lifecycle', () => {
  it('create -> get -> list -> update -> delete (full lifecycle)', async () => {
    const api = treaty<App>(app)
    const BEARER = { headers: { authorization: 'Bearer token' } }

    // CREATE via Eden Treaty (typed response: { data: User | null, error: ..., status })
    const created = await (api.users as any).post({ name: 'grace', age: 40 }, BEARER)
    expect(created.error).toBeNull()
    expect(created.status).toBe(201)
    expect(created.data?.name).toBe('grace')
    expect(typeof created.data?.id).toBe('number')
    const id = created.data!.id

    // GET single via raw handle (param coercion: string id -> number in route)
    const gotRes = await app.handle(new Request(`http://localhost/users/${id}`))
    expect(gotRes.status).toBe(200)
    expect((await gotRes.json()).name).toBe('grace')

    // LIST — confirms created user appears
    const listed = await (api.users as any).get()
    expect(listed.status).toBe(200)
    expect(Array.isArray(listed.data)).toBe(true)
    expect(listed.data!.length).toBe(1)

    // UPDATE via raw handle
    const updatedRes = await app.handle(new Request(`http://localhost/users/${id}`, {
      method: 'PUT',
      headers: { 'content-type': 'application/json', authorization: 'Bearer token' },
      body: JSON.stringify({ name: 'grace-updated', age: 41 }),
    }))
    expect(updatedRes.status).toBe(200)
    expect((await updatedRes.json()).name).toBe('grace-updated')

    // DELETE via raw handle — returns 204 (no content)
    const delRes = await app.handle(new Request(`http://localhost/users/${id}`, {
      method: 'DELETE',
      headers: { authorization: 'Bearer token' },
    }))
    expect(delRes.status).toBe(204)

    // REGRESSION: GET after delete -> 404
    const afterDelete = await app.handle(new Request(`http://localhost/users/${id}`))
    expect(afterDelete.status).toBe(404)
  })
})

// ---------------------------------------------------------------------------
// 5. OpenAPI document — lists all CRUD routes
// ---------------------------------------------------------------------------

describe('OpenAPI document', () => {
  it('GET /openapi/json -> 200, openapi 3.0.3, paths include /users/ and /users/{id}', async () => {
    const res = await app.handle(new Request('http://localhost/openapi/json'))
    expect(res.status).toBe(200)
    const spec = await res.json()
    // openapi version is 3.0.3 (from @elysiajs/openapi)
    expect(spec.openapi).toBe('3.0.3')
    // Plugin prefix + trailing slash: Elysia registers the list route as '/users/'
    expect(spec.paths['/users/']).toBeDefined()
    // Param routes: registered as '/users/{id}' in the OpenAPI doc
    expect(spec.paths['/users/{id}']).toBeDefined()
    // Both GET (list) and POST (create) are registered on /users/
    expect(spec.paths['/users/'].get).toBeDefined()
    expect(spec.paths['/users/'].post).toBeDefined()
    // GET, PUT, DELETE on /users/{id}
    expect(spec.paths['/users/{id}'].get).toBeDefined()
    expect(spec.paths['/users/{id}'].put).toBeDefined()
    expect(spec.paths['/users/{id}'].delete).toBeDefined()
    // Top-level keys present
    const keys = Object.keys(spec)
    expect(keys).toContain('openapi')
    expect(keys).toContain('info')
    expect(keys).toContain('paths')
  })
})

