### source/app.ts
```ts
/**
 * Capstone: type-safe CRUD service
 *
 * Combines every prior level:
 *   L0 — app.handle() in-process test seam
 *   L1 — TypeBox t schemas on every body / param
 *   L2 — centralized onError + bearer-auth guard on mutations
 *   L3 — Eden Treaty integration test client
 *   L4 — @elysiajs/openapi auto-doc listing all routes
 *
 * Every schema used at runtime is also reflected in the OpenAPI document at /openapi/json.
 */

import { Elysia, t } from 'elysia'
import { openapi } from '@elysiajs/openapi'

// ---------------------------------------------------------------------------
// Domain types and in-memory store
// ---------------------------------------------------------------------------

export interface User {
  id: number
  name: string
  age: number
}

const db = new Map<number, User>()
let nextId = 1

/** Reset state (called in tests to isolate runs) */
export function resetDb(): void {
  db.clear()
  nextId = 1
}

// ---------------------------------------------------------------------------
// Custom error
// ---------------------------------------------------------------------------

export class NotFoundError extends Error {
  constructor(public readonly entity: string) {
    super(`${entity} not found`)
  }
}

// ---------------------------------------------------------------------------
// Reusable TypeBox schemas
// ---------------------------------------------------------------------------

const UserBody = t.Object({
  name: t.String({ minLength: 1 }),
  age: t.Number({ minimum: 0 }),
})

const UserResponse = t.Object({
  id: t.Number(),
  name: t.String(),
  age: t.Number(),
})

const UserIdParam = t.Object({ id: t.Number() })

// ---------------------------------------------------------------------------
// CRUD plugin (exported for composition testing)
// ---------------------------------------------------------------------------

export const usersPlugin = new Elysia({ prefix: '/users' })
  // --- read routes (no auth) ---
  .get('/', () => Array.from(db.values()))
  .get('/:id', ({ params: { id } }) => {
    const u = db.get(id)
    if (!u) throw new NotFoundError('user')
    return u
  }, { params: UserIdParam })
  // --- mutation routes (bearer guard via .guard) ---
  .guard(
    {
      // Use Optional(String) so a missing header gives 401 via beforeHandle
      // rather than 422 via schema validation. A required TemplateLiteral would
      // fire schema validation first (422) before beforeHandle sees the request.
      headers: t.Object({
        authorization: t.Optional(t.String()),
      }),
      beforeHandle({ headers, status }) {
        if (!headers.authorization?.startsWith('Bearer ')) {
          return status(401, { error: 'unauthorized' })
        }
      },
    },
    (app) =>
      app
        .post('/', ({ body, status }) => {
          const u: User = { id: nextId++, ...body }
          db.set(u.id, u)
          return status(201, u)
        }, {
          body: UserBody,
          response: { 201: UserResponse },
        })
        .put('/:id', ({ params: { id }, body }) => {
          const existing = db.get(id)
          if (!existing) throw new NotFoundError('user')
          const updated: User = { id, ...body }
          db.set(id, updated)
          return updated
        }, {
          params: UserIdParam,
          body: UserBody,
        })
        .delete('/:id', ({ params: { id }, status }) => {
          if (!db.has(id)) throw new NotFoundError('user')
          db.delete(id)
          return status(204)
        }, {
          params: UserIdParam,
        }),
  )

// ---------------------------------------------------------------------------
// Root application
// ---------------------------------------------------------------------------

export const app = new Elysia()
  .use(openapi())
  .error({ NOT_FOUND: NotFoundError })
  .onError(({ code, error, status }) => {
    if (code === 'NOT_FOUND') {
      return status(404, { error: (error as NotFoundError).message })
    }
    if (code === 'VALIDATION') {
      return status(422, { error: 'validation', detail: (error as any).all ?? [] })
    }
  })
  .use(usersPlugin)

export type App = typeof app

```

