```sh
#!/usr/bin/env bash
# ci.sh — headless CI gate for the Elysia capstone CRUD service
#
# Usage:
#   bash ci.sh
#
# Exit codes:
#   0 — CI PASSED (bun install succeeded, bun test all pass)
#   1 — CI FAILED (bun install failed or bun test has ≥1 failure)
#
# This script is the pass/fail gate for the capstone:
#   - Installs dependencies fresh (bun install)
#   - Runs the full test suite (bun test)
#   - Branches on the real exit code (no pipe — avoids masking bun's exit code)
#   - Prints CI PASSED or CI FAILED and mirrors the exit code

# Bun may not be on the subagent PATH — always set it explicitly.
export PATH="$HOME/.bun/bin:$PATH"

SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
cd "$SCRIPT_DIR"

echo "=== ElysiaJS Capstone CI Gate ==="
echo "Working directory: $(pwd)"
echo "Bun version: $(bun --version)"
echo ""

# Step 1: Install dependencies (set -e applies here: install must succeed)
echo "--- bun install ---"
bun install
INSTALL_EXIT=$?
if [ "$INSTALL_EXIT" -ne 0 ]; then
  echo "CI FAILED (bun install exit code: $INSTALL_EXIT)"
  exit "$INSTALL_EXIT"
fi
echo ""

# Step 2: Run tests — capture exit code WITHOUT piping (piping masks bun's real exit code).
# Note: do NOT run under set -e for the bun test line; capture $? instead.
echo "--- bun test ---"
bun test >ci-test-output.txt 2>&1
BUN_EXIT=$?

# Print the captured output so it appears in any log redirect
cat ci-test-output.txt

echo ""
if [ "$BUN_EXIT" -eq 0 ]; then
  echo "=========================================="
  echo "CI PASSED"
  echo "=========================================="
else
  echo "=========================================="
  echo "CI FAILED (bun test exit code: $BUN_EXIT)"
  echo "=========================================="
fi

exit "$BUN_EXIT"

