### source/capstone.test.mjs
```mjs
/**
 * L-capstone POC — Full in-memory CRUD API with middleware stack
 *
 * Stack: secureHeaders + explicit CORS + @hono/zod-validator body validation + Bearer JWT guard
 * Test seam: app.request("/path", init?) — no port, no network, Web API Response
 *
 * Resources: GET /items, GET /items/:id,
 *            POST /items (guarded), PUT /items/:id (guarded), DELETE /items/:id (guarded)
 *
 * CI discipline: node --test capstone.test.mjs > out.txt 2>&1; echo "EXIT=$?" >> out.txt
 * Exit codes captured via redirect, NOT pipe — pipe masks non-zero exits in zsh.
 */

import { describe, it, beforeEach } from 'node:test';
import assert from 'node:assert/strict';
import { Hono } from 'hono';
import { secureHeaders } from 'hono/secure-headers';
import { cors } from 'hono/cors';
import { zValidator } from '@hono/zod-validator';
import { z } from 'zod';
import { SignJWT, jwtVerify } from 'jose';

// ─── JWT helpers ──────────────────────────────────────────────────────────────
const JWT_SECRET = new TextEncoder().encode('capstone-test-secret-32-bytes-00');

async function mintToken(payload = { sub: 'test-user' }) {
  return new SignJWT(payload)
    .setProtectedHeader({ alg: 'HS256' })
    .setIssuedAt()
    .setExpirationTime('5m')
    .sign(JWT_SECRET);
}

// ─── In-memory store ──────────────────────────────────────────────────────────
let store = [];
let nextId = 1;
function resetStore() {
  store = [];
  nextId = 1;
}

// ─── Schemas ──────────────────────────────────────────────────────────────────
const itemBody = z.object({
  name: z.string().min(1, 'name must be non-empty'),
  qty: z.number().int().nonnegative('qty must be >= 0'),
});

// ─── Middleware: Bearer JWT guard ─────────────────────────────────────────────
async function bearerGuard(c, next) {
  const authHeader = c.req.header('authorization') ?? '';
  const token = authHeader.startsWith('Bearer ') ? authHeader.slice(7) : null;
  if (!token) {
    return c.json({ error: 'unauthorized' }, 401);
  }
  try {
    await jwtVerify(token, JWT_SECRET);
  } catch {
    return c.json({ error: 'unauthorized' }, 401);
  }
  return next();
}

// ─── App (correct, fully guarded) ─────────────────────────────────────────────
const app = new Hono();

app.use('*', secureHeaders());
app.use('*', cors({
  origin: 'https://example.com',
  allowMethods: ['GET', 'POST', 'PUT', 'DELETE'],
}));

// GET /items — list all (no auth)
app.get('/items', (c) => c.json(store));

// GET /items/:id — read one (no auth)
app.get('/items/:id', (c) => {
  const id = Number(c.req.param('id'));
  const item = store.find((i) => i.id === id);
  if (!item) return c.json({ error: 'not found' }, 404);
  return c.json(item);
});

// POST /items — create (guarded + validated)
app.post(
  '/items',
  bearerGuard,
  zValidator('json', itemBody),
  (c) => {
    const data = c.req.valid('json');
    const item = { id: nextId++, ...data };
    store.push(item);
    return c.json(item, 201);
  }
);

// PUT /items/:id — update (guarded + validated)
app.put(
  '/items/:id',
  bearerGuard,
  zValidator('json', itemBody),
  (c) => {
    const id = Number(c.req.param('id'));
    const idx = store.findIndex((i) => i.id === id);
    if (idx === -1) return c.json({ error: 'not found' }, 404);
    const data = c.req.valid('json');
    store[idx] = { id, ...data };
    return c.json(store[idx]);
  }
);

// DELETE /items/:id — delete (guarded) — CORRECTLY guarded
app.delete('/items/:id', bearerGuard, (c) => {
  const id = Number(c.req.param('id'));
  const idx = store.findIndex((i) => i.id === id);
  if (idx === -1) return c.json({ error: 'not found' }, 404);
  store.splice(idx, 1);
  return new Response(null, { status: 204 });
});

// ─── Tests ────────────────────────────────────────────────────────────────────

describe('L-capstone — CRUD lifecycle + middleware guards', () => {
  let token;

  beforeEach(async () => {
    resetStore();
    token = await mintToken();
  });

  // ── Middleware assertions ──

  it('secureHeaders: X-Frame-Options is set on GET /items', async () => {
    const res = await app.request('/items');
    assert.equal(res.status, 200);
    const xfo = res.headers.get('x-frame-options');
    console.log('X-Frame-Options:', xfo);
    assert.ok(xfo !== null, 'X-Frame-Options must be present');
  });

  it('CORS: Access-Control-Allow-Origin echoes configured origin', async () => {
    const res = await app.request('/items', {
      headers: { origin: 'https://example.com' },
    });
    assert.equal(res.status, 200);
    const acao = res.headers.get('access-control-allow-origin');
    console.log('CORS Allow-Origin:', acao);
    assert.equal(acao, 'https://example.com');
  });

  // ── Auth guard assertions ──

  it('POST /items without Bearer → 401', async () => {
    const res = await app.request('/items', {
      method: 'POST',
      headers: { 'content-type': 'application/json' },
      body: JSON.stringify({ name: 'widget', qty: 5 }),
    });
    const body = await res.json();
    console.log('POST no-auth:', res.status, JSON.stringify(body));
    assert.equal(res.status, 401);
    assert.equal(body.error, 'unauthorized');
  });

  it('PUT /items/:id without Bearer → 401', async () => {
    const res = await app.request('/items/1', {
      method: 'PUT',
      headers: { 'content-type': 'application/json' },
      body: JSON.stringify({ name: 'widget', qty: 5 }),
    });
    assert.equal(res.status, 401);
  });

  it('DELETE /items/:id without Bearer → 401 (the fixed bug)', async () => {
    // First create an item with valid auth
    await app.request('/items', {
      method: 'POST',
      headers: { 'content-type': 'application/json', authorization: `Bearer ${token}` },
      body: JSON.stringify({ name: 'widget', qty: 5 }),
    });
    // Try to delete without auth — must be blocked
    const delRes = await app.request('/items/1', { method: 'DELETE' });
    console.log('DELETE no-auth:', delRes.status);
    assert.equal(delRes.status, 401, 'DELETE without Bearer must be blocked (401)');
  });

  // ── Zod validation ──

  it('POST /items with invalid body (empty name, negative qty) → 400', async () => {
    const res = await app.request('/items', {
      method: 'POST',
      headers: { 'content-type': 'application/json', authorization: `Bearer ${token}` },
      body: JSON.stringify({ name: '', qty: -1 }),
    });
    const body = await res.json();
    console.log('POST invalid body:', res.status, JSON.stringify(body));
    assert.equal(res.status, 400);
    assert.equal(body.success, false);
    assert.equal(body.error.name, 'ZodError');
  });

  // ── Full CRUD lifecycle ──

  it('Full CRUD lifecycle: create → read → list → update → delete → 404', async () => {
    // CREATE
    const createRes = await app.request('/items', {
      method: 'POST',
      headers: { 'content-type': 'application/json', authorization: `Bearer ${token}` },
      body: JSON.stringify({ name: 'sprocket', qty: 42 }),
    });
    assert.equal(createRes.status, 201);
    const created = await createRes.json();
    console.log('POST 201:', JSON.stringify(created));
    assert.equal(created.id, 1);
    assert.equal(created.name, 'sprocket');
    assert.equal(created.qty, 42);

    // READ one
    const readRes = await app.request('/items/1');
    assert.equal(readRes.status, 200);
    const readItem = await readRes.json();
    console.log('GET /items/1:', JSON.stringify(readItem));
    assert.deepEqual(readItem, { id: 1, name: 'sprocket', qty: 42 });

    // LIST all
    const listRes = await app.request('/items');
    assert.equal(listRes.status, 200);
    const list = await listRes.json();
    console.log('GET /items (list):', JSON.stringify(list));
    assert.equal(list.length, 1);
    assert.equal(list[0].id, 1);

    // UPDATE
    const updateRes = await app.request('/items/1', {
      method: 'PUT',
      headers: { 'content-type': 'application/json', authorization: `Bearer ${token}` },
      body: JSON.stringify({ name: 'sprocket-v2', qty: 99 }),
    });
    assert.equal(updateRes.status, 200);
    const updated = await updateRes.json();
    console.log('PUT 200:', JSON.stringify(updated));
    assert.deepEqual(updated, { id: 1, name: 'sprocket-v2', qty: 99 });

    // DELETE (with valid auth)
    const deleteRes = await app.request('/items/1', {
      method: 'DELETE',
      headers: { authorization: `Bearer ${token}` },
    });
    console.log('DELETE 204 status:', deleteRes.status);
    assert.equal(deleteRes.status, 204);

    // Verify gone: GET /items/1 → 404
    const goneRes = await app.request('/items/1');
    const goneBody = await goneRes.json();
    console.log('GET /items/1 after delete:', goneRes.status, JSON.stringify(goneBody));
    assert.equal(goneRes.status, 404);
    assert.equal(goneBody.error, 'not found');

    // Verify list is empty
    const emptyListRes = await app.request('/items');
    const emptyList = await emptyListRes.json();
    console.log('GET /items after delete:', JSON.stringify(emptyList));
    assert.equal(emptyList.length, 0);
  });

  // ── 404 for unknown resource ──

  it('GET /items/9999 (nonexistent) → 404 not found', async () => {
    const res = await app.request('/items/9999');
    const body = await res.json();
    console.log('GET /items/9999:', res.status, JSON.stringify(body));
    assert.equal(res.status, 404);
    assert.equal(body.error, 'not found');
  });
});

