### source/L-capstone-streaming-chat.spec.ts
```ts
// Capstone — all five chat components composed into one working streaming chat, in real Chromium.
// Conversation renders with aligned message rows + a date marker; an attachment transitions
// uploading→done (shimmer on→off); an assistant reply streams from a shimmer placeholder into text
// while the scroller auto-scrolls to the end; jump-to-message scrolls an earlier message into view.
import { test, expect } from "@playwright/test"

const rect = (el: Element) => {
  const r = el.getBoundingClientRect()
  return { top: Math.round(r.top), bottom: Math.round(r.bottom) }
}

test("conversation renders: date Marker + aligned Message rows + Bubble variants", async ({ page }) => {
  await page.goto("/?h=chat")
  await expect(page.getByTestId("viewport")).toBeVisible()
  // date separator
  const marker = page.getByTestId("day-marker")
  await expect(marker).toHaveAttribute("data-variant", "separator")
  // user row (msg-0, i%2==0) is end-aligned with a secondary bubble; assistant (msg-1) start/default
  const userRow = page.getByTestId("row-msg-0")
  const botRow = page.getByTestId("row-msg-1")
  await expect(userRow).toHaveAttribute("data-align", "end")
  await expect(botRow).toHaveAttribute("data-align", "start")
  expect(await userRow.locator("[data-slot=bubble]").first().getAttribute("data-variant")).toBe("secondary")
  expect(await botRow.locator("[data-slot=bubble]").first().getAttribute("data-variant")).toBe("default")
})

test("Attachment transitions uploading → done (shimmer token present, state flips)", async ({ page }) => {
  await page.goto("/?h=chat")
  const att = page.getByTestId("att")
  await expect(att).toHaveAttribute("data-state", "uploading")
  // the shimmer token lives on the title; activation is the parent's data-state (see L5)
  expect(await page.getByTestId("att-title").getAttribute("class")).toContain(
