  await page.getByTestId("finish-upload").click()
  await expect(att).toHaveAttribute("data-state", "done") // shimmer now inert
})

test("streamed assistant reply: shimmer 'Thinking…' → real text, auto-scrolls into view", async ({ page }) => {
  await page.goto("/?h=chat")
  const vp = page.getByTestId("viewport")
  await expect(vp).toBeVisible()
  await page.getByTestId("send").click()
  // placeholder appears immediately
  await expect(page.getByTestId("thinking")).toBeVisible()
  // streamed text replaces it (botId = msg-13 on the first send)
  await expect(page.getByTestId("text-msg-13")).toHaveText("Sure, here is the answer.", { timeout: 3000 })
  await expect(page.getByTestId("thinking")).toHaveCount(0)
  // the new assistant bubble auto-scrolled into the viewport
  await page.waitForTimeout(300)
  const vpR = await vp.evaluate(rect)
  const botR = await page.getByTestId("row-msg-13").evaluate(rect)
  expect(botR.bottom).toBeLessThanOrEqual(vpR.bottom + 8)
  expect(botR.top).toBeGreaterThanOrEqual(vpR.top - 8)
})

test("jump-to-message scrolls an earlier message into view", async ({ page }) => {
  await page.goto("/?h=chat")
  const vp = page.getByTestId("viewport")
  await expect(vp).toBeVisible()
  await page.waitForTimeout(300)
  const vpR = await vp.evaluate(rect)
  // at the bottom, msg-0 is above the viewport
  const before = await page.getByTestId("msg-0").evaluate(rect)
  expect(before.bottom).toBeLessThan(vpR.top)
  await page.getByTestId("jump-first").click()
  await page.waitForTimeout(450)
  const after = await page.getByTestId("msg-0").evaluate(rect)
  // now msg-0 intersects the viewport
  expect(after.bottom).toBeGreaterThan(vpR.top)
  expect(after.top).toBeLessThan(vpR.bottom)
})

