// Capstone harness — a full streaming chat composing all five chat components, in real Chromium.
// Mounted via App.tsx at /?h=chat. Driven by e2e/L-capstone-streaming-chat.spec.ts.
// Deterministic ids (msg-N) + setTimeout streaming — no Math.random / Date.now / new Date.
import * as React from "react"
import {
  MessageScrollerProvider,
  MessageScroller,
  MessageScrollerViewport,
  MessageScrollerContent,
  MessageScrollerItem,
  useMessageScroller,
} from "@/components/ui/message-scroller"
import { Message, MessageContent, MessageGroup } from "@/components/ui/message"
import { Bubble, BubbleContent } from "@/components/ui/bubble"
import { Marker, MarkerContent } from "@/components/ui/marker"
import {
  Attachment,
  AttachmentMedia,
  AttachmentContent,
  AttachmentTitle,
  AttachmentDescription,
  AttachmentActions,
  AttachmentAction,
} from "@/components/ui/attachment"

type Msg = { id: string; role: "user" | "assistant"; text: string; streaming?: boolean }

function Controls({
  onSend,
  onJumpFirst,
}: {
  onSend: () => void
  onJumpFirst: () => void
}) {
  return (
    <div style={{ display: "flex", gap: 8, padding: 8 }}>
      <button data-testid="send" onClick={onSend}>send</button>
      <button data-testid="jump-first" onClick={onJumpFirst}>jump first</button>
    </div>
  )
}

function JumpButton({ onReady }: { onReady: (fn: () => void) => void }) {
  const { scrollToMessage } = useMessageScroller()
  React.useEffect(() => {
    onReady(() => scrollToMessage("msg-0"))
  }, [onReady, scrollToMessage])
  return null
}

export function ChatHarness() {
  const initial: Msg[] = Array.from({ length: 12 }, (_, i) => ({
    id: `msg-${i}`,
    role: i % 2 === 0 ? "user" : "assistant",
    text: `Message number ${i}`,
  }))
  const [messages, setMessages] = React.useState<Msg[]>(initial)
  const [attState, setAttState] = React.useState<"uploading" | "done">("uploading")
  const nextId = React.useRef(12)
  const jumpRef = React.useRef<() => void>(() => {})

  const send = () => {
    const userId = `msg-${nextId.current++}`
    const botId = `msg-${nextId.current++}`
    setMessages((cur) => [
      ...cur,
      { id: userId, role: "user", text: "What is the answer?" },
      { id: botId, role: "assistant", text: "", streaming: true },
    ])
    window.setTimeout(() => {
      setMessages((cur) =>
        cur.map((m) =>
          m.id === botId ? { ...m, text: "Sure, here is the answer.", streaming: false } : m
        )
      )
    }, 600)
  }

  return (
    <MessageScrollerProvider autoScroll defaultScrollPosition="end">
      <Controls onSend={send} onJumpFirst={() => jumpRef.current()} />
      <button data-testid="finish-upload" onClick={() => setAttState("done")} style={{ margin: 8 }}>
        finish upload
      </button>
      <MessageScroller style={{ height: 400, width: 420, border: "1px solid #ccc" }}>
        <MessageScrollerViewport data-testid="viewport">
          <MessageScrollerContent>
            <JumpButton onReady={(fn) => (jumpRef.current = fn)} />
            <Marker variant="separator" data-testid="day-marker">
              <MarkerContent>Today</MarkerContent>
            </Marker>

            {/* An uploaded file attachment whose state transitions uploading -> done */}
            <Attachment data-testid="att" state={attState} style={{ margin: "0 8px" }}>
              <AttachmentMedia variant="image" />
              <AttachmentContent>
                <AttachmentTitle data-testid="att-title">photo.jpg</AttachmentTitle>
                <AttachmentDescription>2.4 MB</AttachmentDescription>
              </AttachmentContent>
              <AttachmentActions>
                <AttachmentAction data-testid="att-remove" aria-label="remove" />
              </AttachmentActions>
            </Attachment>

            {messages.map((m) => (
              <MessageScrollerItem key={m.id} messageId={m.id} scrollAnchor data-testid={m.id}>
                <MessageGroup>
                  <Message align={m.role === "user" ? "end" : "start"} data-testid={`row-${m.id}`}>
                    <MessageContent>
                      <Bubble
                        variant={m.role === "user" ? "secondary" : "default"}
                        align={m.role === "user" ? "end" : "start"}
                      >
                        <BubbleContent>
                          {m.streaming ? (
                            <span className="shimmer" data-testid="thinking">Thinking…</span>
                          ) : (
                            <span data-testid={`text-${m.id}`}>{m.text}</span>
                          )}
                        </BubbleContent>
                      </Bubble>
                    </MessageContent>
                  </Message>
                </MessageGroup>
              </MessageScrollerItem>
            ))}
          </MessageScrollerContent>
        </MessageScrollerViewport>
      </MessageScroller>
    </MessageScrollerProvider>
  )
}

