```js
// green.test.js — the PASSING end-to-end state + regressions.
//
// Full pipeline: table -> AFTER INSERT trigger -> pgmq queue -> pg_cron worker -> processor.
// We schedule the REAL cron worker ('5 seconds'), but the bounded poll ALSO drives the
// processor inline so the assertions do not hang on cron timing. We separately PROVE the
// cron job fired on its own by reading cron.job_run_details.
//
// Regressions:
//   R1 — a document inserted AFTER the pipeline is already running is still processed.
//   R2 — a document whose processing ERRORS (NULL content) is isolated: it is marked
//        'error' and does NOT abort the batch; the good rows in the same batch still finish.
//
// run: `npm run test:green`

import { test, before, after } from "node:test";
import assert from "node:assert/strict";
import crypto from "node:crypto";
import {
  connect,
  setupPipeline,
  scheduleWorker,
  teardownPipeline,
  insertDocs,
  queueLength,
  docStatuses,
  pollUntil,
  waitForCronRun,
  NS,
} from "./pipeline.js";

let c;
let jobid;

function sha256Hex(s) {
  return crypto.createHash("sha256").update(s, "utf8").digest("hex");
}

before(async () => {
  c = await connect();
  await setupPipeline(c);
  jobid = await scheduleWorker(c);
  console.log(`[green] scheduled cron worker '${NS.cronJob}' -> jobid ${jobid} ('5 seconds')`);
});

after(async () => {
  // Teardown MUST succeed even if the shared client's socket was dropped during the long
  // cron-observation window — otherwise the '5 seconds' cron job leaks. Use a guaranteed
  // FRESH connection for cleanup, and best-effort close the old one.
  try { if (c) await c.end(); } catch { /* socket may already be dead */ }
  const fresh = await connect();
  await teardownPipeline(fresh);
  await fresh.end();
  console.log("[green] cleaned up (fresh conn): cron unscheduled, trigger/function/queue/table dropped");
});

test("end-to-end: insert 3 -> trigger enqueues 3 -> worker drains -> all 'done' with correct result", async () => {
  const contents = ["alpha", "beta-content", "gamma is longer"];
  const ids = await insertDocs(c, contents);
  assert.equal(ids.length, 3);

  // Trigger enqueued synchronously inside the INSERT.
  const qlen = await queueLength(c);
  console.log(`[green] queue_length right after insert = ${qlen}`);
  assert.equal(qlen, 3, "trigger should enqueue exactly 3 messages");

  // Bounded poll until all three are 'done'.
  const predicate = `
    select (count(*) filter (where status = 'done') = 3) as done
      from ${NS.table} where id = any($1)`;
  const res = await pollUntil(c, predicate, [ids], { ticks: 40 });
  assert.ok(res.ok, `all 3 docs should reach 'done' within bound (drained after ~${res.ticks} ticks)`);
  console.log(`[green] all 3 docs reached 'done' after ${res.ticks} processor ticks`);

  // Verify each row's result against an INDEPENDENT Node-computed sha256 (real, not echoed).
  const rows = await docStatuses(c, ids);
  for (let i = 0; i < rows.length; i++) {
    const row = rows[i];
    const content = contents[i];
    assert.equal(row.status, "done");
    assert.ok(row.processed_at, "processed_at must be set");
    assert.equal(row.result.char_count, content.length, "char_count must equal content length");
    assert.equal(
      row.result.sha256,
      sha256Hex(content),
      "DB pgcrypto sha256 must match Node crypto sha256 (real digest, not a placeholder)"
    );
    console.log(`[green] doc ${row.id} done: char_count=${row.result.char_count} sha256=${row.result.sha256.slice(0, 12)}...`);
  }

  // Queue must be empty now (every message pgmq.delete'd on success).
  const finalQ = await queueLength(c);
  assert.equal(finalQ, 0, "queue must be fully drained after processing");
});

test("R1 — a document inserted AFTER the pipeline is running is also processed", async () => {
  const late = "late-arrival-document";
  const [lateId] = await insertDocs(c, [late]);
  console.log(`[green:R1] inserted late doc id=${lateId}`);

  const predicate = `select (status = 'done') as done from ${NS.table} where id = $1`;
  const res = await pollUntil(c, predicate, [lateId], { ticks: 40 });
  assert.ok(res.ok, "late-arriving doc should also reach 'done'");

  const [row] = await docStatuses(c, [lateId]);
  assert.equal(row.status, "done");
  assert.equal(row.result.char_count, late.length);
  assert.equal(row.result.sha256, sha256Hex(late));
  console.log(`[green:R1] late doc ${lateId} processed: sha256=${row.result.sha256.slice(0, 12)}...`);
});

test("R2 — an erroring document is isolated; the good rows in the same batch still complete", async () => {
  // A NULL-content row deliberately raises inside the processor. The good row enqueued
  // alongside it must still reach 'done' — the per-message exception block isolates the
  // failure instead of aborting the whole batch.
  const goodContent = "healthy-row-alongside-the-bad-one";

  // Insert the good row first, then a NULL-content (bad) row. Both trigger-enqueue.
  const [goodId] = await insertDocs(c, [goodContent]);
  const badRes = await c.query(
    `insert into ${NS.table} (content) values (NULL) returning id`
  );
  const badId = badRes.rows[0].id;
  console.log(`[green:R2] good id=${goodId}, bad(null-content) id=${badId}`);

  // Both should now be enqueued.
  const qlen = await queueLength(c);
  assert.ok(qlen >= 2, `both rows should be enqueued (queue_length=${qlen})`);

  // Poll until the good row is done. The bad row must NOT block this.
  const goodPredicate = `select (status = 'done') as done from ${NS.table} where id = $1`;
  const res = await pollUntil(c, goodPredicate, [goodId], { ticks: 40 });
  assert.ok(res.ok, "good row must complete even though a sibling message errors");

  const [goodRow] = await docStatuses(c, [goodId]);
  assert.equal(goodRow.status, "done");
  assert.equal(goodRow.result.sha256, sha256Hex(goodContent));

  // The bad row is marked 'error' with a captured SQLERRM — and the worker did NOT crash.
  const [badRow] = await docStatuses(c, [badId]);
  assert.equal(badRow.status, "error", "the null-content row must be flagged 'error'");
  assert.ok(badRow.result && badRow.result.error, "error detail must be captured in result");
  console.log(`[green:R2] good ${goodId} done; bad ${badId} status='${badRow.status}' error='${badRow.result.error}'`);
});

test("cron worker actually fired on its own (cron.job_run_details)", async () => {
  // Observe cron's OWN execution, independent of the inline processor poll. Uses a fresh
  // connection per attempt (waitForCronRun) so a dropped backend socket can't fail this.
  // '5 seconds' schedule -> a ~15s bound (60 ticks * 250ms) spans multiple firings.
  const runs = await waitForCronRun(jobid, { ticks: 60 });
  assert.ok(runs && runs.length > 0, `cron job ${jobid} should have at least one run recorded within the bound`);

  console.log(`[green:cron] job_run_details for jobid ${jobid}:`);
  for (const r of runs) {
    console.log(`  runid=${r.runid} status=${r.status} msg=${r.return_message} start=${r.start_time?.toISOString?.() ?? r.start_time}`);
  }
  // At least one recorded run should have succeeded.
  const succeeded = runs.some((r) => r.status === "succeeded");
  assert.ok(succeeded, "at least one cron run should be 'succeeded'");
});

