/**
 * L-capstone integration test
 * Exercises: routes (L5) + sqlite (L7) + password (L10) + websocket (L13) + SSE (L18) + logging + EADDRINUSE (L20)
 *
 * RED: expect(liveEvent.slug).toBe("WRONG-SLUG") — real slug is the one we POSTed
 * GREEN: fix to expect(liveEvent.slug).toBe(slug)
 */
import { test, expect, beforeAll, afterAll } from "bun:test";
import { startServer, demonstrateEADDRINUSE } from "./src/app";
import type { Database } from "bun:sqlite";
import type { Server } from "bun";

let server: Server;
let db: Database;
let baseUrl: string;
let wsUrl: string;

beforeAll(() => {
  const result = startServer({ port: "random" });
  server = result.server;
  db = result.db;
  baseUrl = `http://localhost:${server.port}`;
  wsUrl = `ws://localhost:${server.port}`;
});

afterAll(() => {
  server.stop(true);
  db.close();
});

// ─── Integration: register -> login -> create link -> WS live-update -> read-back ───────────────

test("full create->read->auth->live-update flow", async () => {
  const username = `alice_${Date.now()}`;
  const password = "pw123";
  const slug = `s${Date.now()}`;
  const url = "https://x.com";

  // 1. Register (L10: Bun.password.hash bcrypt internally)
  const regRes = await fetch(`${baseUrl}/api/register`, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({ username, password }),
  });
  expect(regRes.status).toBe(201);
  const regBody = await regRes.json() as { id: number; username: string };
  expect(regBody.username).toBe(username);
  expect(typeof regBody.id).toBe("number");

  // 2. Login -> get token (L10: Bun.password.verify)
  const loginRes = await fetch(`${baseUrl}/api/login`, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({ username, password }),
  });
  expect(loginRes.status).toBe(200);
  const { token } = await loginRes.json() as { token: string };
  expect(typeof token).toBe("string");

  // 3. Open WebSocket subscriber (L13)
  const liveEvents: any[] = [];
  const ws = new WebSocket(`${wsUrl}/ws`, {
    // @ts-ignore — Bun accepts headers in the WebSocket constructor options
    headers: { Authorization: `Bearer ${token}` },
  });

  await new Promise<void>((resolve) => {
    ws.onopen = () => resolve();
  });

  ws.onmessage = (e: MessageEvent) => {
    const data = JSON.parse(e.data as string);
    // Filter for real link-created events (not echos)
    if (data.type === "created") liveEvents.push(data);
  };

  // Small wait to ensure subscription is active
  await Bun.sleep(50);

  // 4. Create short link -> triggers server.publish("links", ...) (L7 + L13)
  const createRes = await fetch(`${baseUrl}/api/links`, {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
      Authorization: `Bearer ${token}`,
    },
    body: JSON.stringify({ slug, url }),
  });
  expect(createRes.status).toBe(201);
  const created = await createRes.json() as { id: number; slug: string; url: string; owner: number };
  expect(created.slug).toBe(slug);
  expect(created.url).toBe(url);

  // 5. Wait for live-update WebSocket event (L13)
  await Bun.sleep(100);
  ws.close();

  expect(liveEvents.length).toBeGreaterThan(0);
  const liveEvent = liveEvents[0];

  // ── GREEN ASSERTION ───────────────────────────────────────────────────────
  // The actual slug is the one we POSTed above (e.g. "s1782576360131")
  expect(liveEvent.slug).toBe(slug);  // GREEN: real slug received via server.publish
  // ─────────────────────────────────────────────────────────────────────────

  // 6. Read-back from sqlite (L7)
  const getRes = await fetch(`${baseUrl}/api/links/${slug}`);
  // 302 redirect means the link exists (or it returned the row JSON in our implementation)
  expect([200, 302, 301]).toContain(getRes.status);
});

// ─── SSE endpoint (L18) ──────────────────────────────────────────────────────

test("SSE /events returns text/event-stream", async () => {
  const res = await fetch(`${baseUrl}/events`);
  expect(res.status).toBe(200);
  expect(res.headers.get("Content-Type")).toContain("text/event-stream");
  const body = await res.text();
  expect(body).toContain("data: hello");
  expect(body).toContain("data: world");
});

// ─── EADDRINUSE failure path (L20) ───────────────────────────────────────────

test("double-bind same port throws EADDRINUSE", () => {
  const result = demonstrateEADDRINUSE(49231);
  expect(result.code).toBe("EADDRINUSE");
  expect(result.message).toContain("49231");
});

