/**
 * L-capstone: Full-stack URL shortener + task tracker
 * Combines: L5 (routes), L7 (sqlite), L10 (password), L13 (websocket), L18 (SSE), L20 (logging + failure path)
 */
import { Database } from "bun:sqlite";

// ── Structured logging (L20) ──────────────────────────────────────────────────
export function log(level: "info" | "error" | "warn", event: string, fields: Record<string, unknown> = {}) {
  console.error(JSON.stringify({ ts: Date.now(), level, event, ...fields }));
}

// ── Database setup (L7) ───────────────────────────────────────────────────────
export function setupDb(dbPath: string = ":memory:"): Database {
  const db = new Database(dbPath);
  db.run("PRAGMA journal_mode = WAL");
  db.run(`
    CREATE TABLE IF NOT EXISTS users (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      username TEXT UNIQUE NOT NULL,
      pw TEXT NOT NULL
    )
  `);
  db.run(`
    CREATE TABLE IF NOT EXISTS links (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      slug TEXT UNIQUE NOT NULL,
      url TEXT NOT NULL,
      owner INTEGER NOT NULL,
      clicks INTEGER DEFAULT 0
    )
  `);
  db.run(`
    CREATE TABLE IF NOT EXISTS tasks (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      title TEXT NOT NULL,
      done INTEGER DEFAULT 0,
      owner INTEGER NOT NULL
    )
  `);
  return db;
}

// ── Simple session store (in-memory for POC) ──────────────────────────────────
const sessions = new Map<string, number>(); // token -> userId

function issueToken(userId: number): string {
  const token = `tok_${userId}_${Math.random().toString(36).slice(2)}`;
  sessions.set(token, userId);
  return token;
}

function getUserId(req: Request): number | null {
  const auth = req.headers.get("Authorization") || "";
  const token = auth.replace(/^Bearer\s+/, "");
  return sessions.get(token) ?? null;
}

// ── Server factory ────────────────────────────────────────────────────────────
export function startServer(opts: { port: number | "random"; dbPath?: string }) {
  const db = setupDb(opts.dbPath ?? ":memory:");

  const insertUser = db.query<{ id: number }, [string, string]>(
    "INSERT INTO users (username, pw) VALUES (?, ?) RETURNING id"
  );
  const selectUser = db.query<{ id: number; pw: string }, [string]>(
    "SELECT id, pw FROM users WHERE username = ?"
  );
  const insertLink = db.query<{ id: number; slug: string; url: string; owner: number; clicks: number }, [string, string, number]>(
    "INSERT INTO links (slug, url, owner) VALUES (?, ?, ?) RETURNING id, slug, url, owner, clicks"
  );
  const selectLink = db.query<{ id: number; slug: string; url: string; owner: number; clicks: number }, [string]>(
    "SELECT id, slug, url, owner, clicks FROM links WHERE slug = ?"
  );
  const selectAllLinks = db.query<{ id: number; slug: string; url: string }, []>(
    "SELECT id, slug, url FROM links"
  );
  const insertTask = db.query<{ id: number; title: string; done: number }, [string, number]>(
    "INSERT INTO tasks (title, owner) VALUES (?, ?) RETURNING id, title, done"
  );
  const selectTasks = db.query<{ id: number; title: string; done: number }, [number]>(
    "SELECT id, title, done FROM tasks WHERE owner = ?"
  );

  const server = Bun.serve({
    port: opts.port === "random" ? 0 : opts.port,

    // Routes (L5)
    routes: {
      // Register user (L10: Bun.password.hash)
      "/api/register": {
        async POST(req) {
          const body = await req.json() as { username: string; password: string };
          const { username, password } = body;
          try {
            const hash = await Bun.password.hash(password, { algorithm: "bcrypt", cost: 4 });
            const row = insertUser.get(username, hash);
            log("info", "user.register", { username, id: row!.id });
            return Response.json({ id: row!.id, username }, { status: 201 });
          } catch (e: any) {
            log("error", "user.register.conflict", { username, message: e.message });
            return Response.json({ error: "Username taken" }, { status: 409 });
          }
        },
      },

      // Login (L10: Bun.password.verify)
      "/api/login": {
        async POST(req) {
          const body = await req.json() as { username: string; password: string };
          const row = selectUser.get(body.username);
          if (!row) return Response.json({ error: "Not found" }, { status: 404 });
          const ok = await Bun.password.verify(body.password, row.pw);
          if (!ok) return Response.json({ error: "Forbidden" }, { status: 403 });
          const token = issueToken(row.id);
          log("info", "user.login", { username: body.username, userId: row.id });
          return Response.json({ token });
        },
      },

      // Create short link (L7 + L13 websocket publish)
      "/api/links": {
        async POST(req) {
          const userId = getUserId(req);
          if (!userId) return Response.json({ error: "Unauthorized" }, { status: 401 });
          const body = await req.json() as { slug: string; url: string };
          try {
            const row = insertLink.get(body.slug, body.url, userId);
            log("info", "link.created", { slug: row!.slug, url: row!.url, owner: userId });
            // Publish live update to WebSocket subscribers (L13)
            server.publish("links", JSON.stringify({ type: "created", slug: row!.slug, url: row!.url }));
            return Response.json(row, { status: 201 });
          } catch (e: any) {
            log("error", "link.slug_conflict", { slug: body.slug, message: e.message });
            return Response.json({ error: "Slug conflict" }, { status: 409 });
          }
        },
        GET(_req) {
          const rows = selectAllLinks.all();
          return Response.json(rows);
        },
      },

      // Redirect short link (L7 read + click count)
      "/api/links/:slug": {
        GET(req) {
          const slug = (req as any).params.slug as string;
          const row = selectLink.get(slug);
          if (!row) return Response.json({ error: "Not found" }, { status: 404 });
          db.run("UPDATE links SET clicks = clicks + 1 WHERE slug = ?", [slug]);
          log("info", "link.redirect", { slug, url: row.url });
          return Response.redirect(row.url, 302);
        },
      },

      // Tasks (L7)
      "/api/tasks": {
        async POST(req) {
          const userId = getUserId(req);
          if (!userId) return Response.json({ error: "Unauthorized" }, { status: 401 });
          const body = await req.json() as { title: string };
          const row = insertTask.get(body.title, userId);
          log("info", "task.created", { title: row!.title, owner: userId });
          server.publish("tasks", JSON.stringify({ type: "task_created", id: row!.id, title: row!.title }));
          return Response.json(row, { status: 201 });
        },
        GET(req) {
          const userId = getUserId(req);
          if (!userId) return Response.json({ error: "Unauthorized" }, { status: 401 });
          return Response.json(selectTasks.all(userId));
        },
      },

      // SSE events endpoint (L18)
      "/events": {
        GET(_req) {
          const stream = new ReadableStream({
            start(controller) {
              controller.enqueue("data: hello\n\n");
              controller.enqueue("data: world\n\n");
              controller.close();
            },
          });
          return new Response(stream, {
            headers: { "Content-Type": "text/event-stream", "Cache-Control": "no-cache" },
          });
        },
      },

      // Health ping
      "/api/ping": new Response("pong"),
    },

    // Fallback: WebSocket upgrade (L13) or 404
    fetch(req, server) {
      const url = new URL(req.url);
      if (url.pathname === "/ws") {
        const userId = getUserId(req) ?? 0;
        const upgraded = server.upgrade(req, { data: { userId } });
        if (upgraded) return undefined;
        return new Response("Upgrade required", { status: 426 });
      }
      return new Response("Not Found", { status: 404 });
    },

    // WebSocket handlers (L13)
    websocket: {
      open(ws) {
        ws.subscribe("links");
        ws.subscribe("tasks");
        log("info", "ws.connected", { userId: (ws.data as any).userId });
      },
      message(ws, msg) {
        // Echo back for testing
        ws.send(JSON.stringify({ echo: msg }));
      },
      close(ws) {
        log("info", "ws.disconnected", { userId: (ws.data as any).userId });
      },
    },
  });

  return { server, db };
}

// ── L20 failure-path demo: EADDRINUSE ─────────────────────────────────────────
export function demonstrateEADDRINUSE(port: number): { code: string; message: string } {
  const s1 = Bun.serve({ port, fetch: () => new Response("ok") });
  try {
    const s2 = Bun.serve({ port, fetch: () => new Response("ok") });
    s2.stop(true);
    s1.stop(true);
    return { code: "NONE", message: "No error" };
  } catch (e: any) {
    log("error", "port.eaddrinuse", { port, code: e.code, message: e.message });
    s1.stop(true);
    return { code: e.code, message: e.message };
  }
}

