-- P27 Capstone: Multi-tenant notes/tasks app schema migrations
-- Applied versioned via migration table. All DDL is idempotent on re-run.

-- ── Migration tracking ────────────────────────────────────────────────────────
CREATE TABLE IF NOT EXISTS schema_migrations (
  version     INT     PRIMARY KEY,
  name        TEXT    NOT NULL,
  applied_at  TIMESTAMPTZ NOT NULL DEFAULT now()
);

-- ── Migration V1: extensions + tenants ───────────────────────────────────────
DO $$ BEGIN
  IF NOT EXISTS (SELECT 1 FROM schema_migrations WHERE version = 1) THEN

    CREATE EXTENSION IF NOT EXISTS "uuid-ossp";
    CREATE EXTENSION IF NOT EXISTS vector;
    CREATE EXTENSION IF NOT EXISTS pg_trgm;
    CREATE EXTENSION IF NOT EXISTS pg_stat_statements;

    CREATE TABLE IF NOT EXISTS tenants (
      id         UUID    PRIMARY KEY DEFAULT uuid_generate_v4(),
      name       TEXT    NOT NULL UNIQUE,
      created_at TIMESTAMPTZ NOT NULL DEFAULT now()
    );

    INSERT INTO schema_migrations(version, name)
    VALUES (1, 'extensions-and-tenants');

    RAISE NOTICE 'Migration V1 applied: extensions + tenants';
  ELSE
    RAISE NOTICE 'Migration V1 already applied, skipping';
  END IF;
END $$;

-- ── Migration V2: notes (JSONB + FTS + pgvector + trgm) ──────────────────────
DO $$ BEGIN
  IF NOT EXISTS (SELECT 1 FROM schema_migrations WHERE version = 2) THEN

    CREATE TABLE IF NOT EXISTS notes (
      id          UUID    PRIMARY KEY DEFAULT uuid_generate_v4(),
      tenant_id   UUID    NOT NULL REFERENCES tenants(id) ON DELETE CASCADE,
      title       TEXT    NOT NULL CHECK (char_length(title) BETWEEN 1 AND 500),
      body        TEXT    NOT NULL DEFAULT '',
      tags        TEXT[]  NOT NULL DEFAULT '{}',
      metadata    JSONB   NOT NULL DEFAULT '{}',
      -- Generated tsvector for full-text search (EN dictionary)
      search_vec  TSVECTOR GENERATED ALWAYS AS (
        to_tsvector('english', coalesce(title,'') || ' ' || coalesce(body,''))
      ) STORED,
      -- 3-dimensional embedding for keyless synthetic pgvector demo
      embedding   VECTOR(3),
      created_at  TIMESTAMPTZ NOT NULL DEFAULT now(),
      updated_at  TIMESTAMPTZ NOT NULL DEFAULT now()
    );

    -- GIN index on the generated tsvector for fast full-text search
    CREATE INDEX IF NOT EXISTS notes_search_vec_gin
      ON notes USING gin(search_vec);

    -- GIN index on tags array for fast containment queries
    CREATE INDEX IF NOT EXISTS notes_tags_gin
      ON notes USING gin(tags);

    -- GIN index on metadata JSONB for fast JSONB path lookups
    CREATE INDEX IF NOT EXISTS notes_metadata_gin
      ON notes USING gin(metadata);

    -- pg_trgm index on title for fuzzy/LIKE search
    CREATE INDEX IF NOT EXISTS notes_title_trgm
      ON notes USING gin(title gin_trgm_ops);

    -- HNSW index on embedding for fast approximate nearest-neighbor search
    CREATE INDEX IF NOT EXISTS notes_embedding_hnsw
      ON notes USING hnsw(embedding vector_l2_ops)
      WITH (m = 8, ef_construction = 32);

    -- RLS: enable row-level security
    ALTER TABLE notes ENABLE ROW LEVEL SECURITY;

    -- Superuser bypass: postgres role is exempt from RLS by default
    -- Policy for tenant isolation via session variable app.tenant_id
    CREATE POLICY notes_tenant_isolation ON notes
      USING (tenant_id = current_setting('app.tenant_id', true)::uuid)
      WITH CHECK (tenant_id = current_setting('app.tenant_id', true)::uuid);

    INSERT INTO schema_migrations(version, name)
    VALUES (2, 'notes-table-with-indexes-and-rls');

    RAISE NOTICE 'Migration V2 applied: notes table with FTS + trgm + pgvector + RLS';
  ELSE
    RAISE NOTICE 'Migration V2 already applied, skipping';
  END IF;
END $$;

-- ── Migration V3: tasks (FK, constraints, status enum-style check) ────────────
DO $$ BEGIN
  IF NOT EXISTS (SELECT 1 FROM schema_migrations WHERE version = 3) THEN

    CREATE TABLE IF NOT EXISTS tasks (
      id          UUID    PRIMARY KEY DEFAULT uuid_generate_v4(),
      tenant_id   UUID    NOT NULL REFERENCES tenants(id) ON DELETE CASCADE,
      note_id     UUID    REFERENCES notes(id) ON DELETE SET NULL,
      title       TEXT    NOT NULL CHECK (char_length(title) BETWEEN 1 AND 200),
      status      TEXT    NOT NULL DEFAULT 'open'
                          CHECK (status IN ('open','in_progress','done','cancelled')),
      assigned_to TEXT,
      counter     INT     NOT NULL DEFAULT 0 CHECK (counter >= 0),
      created_at  TIMESTAMPTZ NOT NULL DEFAULT now(),
      updated_at  TIMESTAMPTZ NOT NULL DEFAULT now()
    );

    -- RLS on tasks too
    ALTER TABLE tasks ENABLE ROW LEVEL SECURITY;

    CREATE POLICY tasks_tenant_isolation ON tasks
      USING (tenant_id = current_setting('app.tenant_id', true)::uuid)
      WITH CHECK (tenant_id = current_setting('app.tenant_id', true)::uuid);

    INSERT INTO schema_migrations(version, name)
    VALUES (3, 'tasks-table-with-rls');

    RAISE NOTICE 'Migration V3 applied: tasks table with FK + CHECK + RLS';
  ELSE
    RAISE NOTICE 'Migration V3 already applied, skipping';
  END IF;
END $$;

-- ── Migration V4: pg_notify trigger on note creation ─────────────────────────
DO $$ BEGIN
  IF NOT EXISTS (SELECT 1 FROM schema_migrations WHERE version = 4) THEN

    CREATE OR REPLACE FUNCTION notify_note_created()
    RETURNS TRIGGER LANGUAGE plpgsql AS $func$
    BEGIN
      PERFORM pg_notify(
        'note_created',
        json_build_object(
          'id',        NEW.id,
          'tenant_id', NEW.tenant_id,
          'title',     NEW.title,
          'op',        TG_OP
        )::text
      );
      RETURN NEW;
    END;
    $func$;

    DROP TRIGGER IF EXISTS trg_note_created ON notes;
    CREATE TRIGGER trg_note_created
      AFTER INSERT ON notes
      FOR EACH ROW EXECUTE FUNCTION notify_note_created();

    INSERT INTO schema_migrations(version, name)
    VALUES (4, 'pg-notify-trigger-on-note-created');

    RAISE NOTICE 'Migration V4 applied: pg_notify trigger on note creation';
  ELSE
    RAISE NOTICE 'Migration V4 already applied, skipping';
  END IF;
END $$;

-- ── Migration V5: app role for RLS tenant isolation demo ─────────────────────
DO $$ BEGIN
  IF NOT EXISTS (SELECT 1 FROM schema_migrations WHERE version = 5) THEN

    -- Create role if it does not exist (DROP+RECREATE is safe in a test DB)
    IF NOT EXISTS (SELECT FROM pg_roles WHERE rolname = 'p27_approle') THEN
      CREATE ROLE p27_approle LOGIN PASSWORD 'approle_pw27';
    END IF;

    GRANT CONNECT ON DATABASE poc27 TO p27_approle;
    GRANT SELECT, INSERT, UPDATE, DELETE ON TABLE tenants TO p27_approle;
    GRANT SELECT, INSERT, UPDATE, DELETE ON TABLE notes   TO p27_approle;
    GRANT SELECT, INSERT, UPDATE, DELETE ON TABLE tasks   TO p27_approle;
    GRANT SELECT ON TABLE schema_migrations TO p27_approle;

    INSERT INTO schema_migrations(version, name)
    VALUES (5, 'app-role-for-rls-demo');

    RAISE NOTICE 'Migration V5 applied: app role p27_approle created';
  ELSE
    RAISE NOTICE 'Migration V5 already applied, skipping';
  END IF;
END $$;

