### source/poc.test.mjs
```mjs
/**
 * poc.test.mjs — L-capstone: auth-verify-middleware CI gate
 *
 * GREEN version: all assertions correct.
 *
 * Proves that verifyToken() / createVerifier() enforce the secure defaults
 * that jose's raw jwtVerify() does NOT apply by default:
 *   1. aud NOT checked by default (insecure); enforced only with { audience } option
 *   2. iss NOT checked by default (insecure); enforced only with { issuer } option
 *   3. algorithms allowlist enforced — prevents algorithm confusion (JOSEAlgNotAllowed)
 *   4. Tampered token → JWSSignatureVerificationFailed
 *   5. Expired token (past exp, no sleep) → JWTExpired
 *   6. Happy path: valid token passes all checks → payload verified
 *   7. createVerifier factory pre-binds key+opts → same guarantees via single-arg call
 */

import { test } from 'node:test';
import assert from 'node:assert/strict';
import { generateKeyPair, SignJWT, jwtVerify } from 'jose';
import { verifyToken, createVerifier } from './auth-middleware.mjs';

const ISSUER = 'https://auth.example.com';
const AUDIENCE = 'my-api';
const ALGORITHMS = ['ES256'];

// ── Shared key pair (generated once for all tests) ──────────────────────────
const { privateKey, publicKey } = await generateKeyPair('ES256');

/** Helper: mint a valid token with the given claim/header overrides */
async function mintToken(claimsOverride = {}, headerOverride = { alg: 'ES256' }) {
  return new SignJWT({ sub: 'user123', aud: AUDIENCE, iss: ISSUER, ...claimsOverride })
    .setProtectedHeader(headerOverride)
    .setIssuedAt()
    .setExpirationTime('1h')
    .sign(privateKey);
}

// ── TEST 1: aud NOT enforced by default (insecure gap confirmed) ─────────────
// Correct assertion: jwtVerify WITHOUT audience option ACCEPTS any aud claim.
// This is the gotcha — the test now correctly confirms the default behavior.
test('aud NOT enforced by default: jwtVerify accepts wrong-audience token without audience option', async () => {
  const jwt = await mintToken({ aud: 'some-other-service' });

  // Without { audience } option, jose DOES NOT check aud — this succeeds
  const { payload } = await jwtVerify(jwt, publicKey);
  assert.strictEqual(payload.aud, 'some-other-service', 'aud claim present in payload');
  assert.strictEqual(payload.sub, 'user123', 'sub present in payload');
  // Getting here confirms: aud is NOT enforced by default
});

// ── TEST 2: verifyToken enforces wrong audience → JWTClaimValidationFailed ───
test('verifyToken enforces audience: wrong aud → JWTClaimValidationFailed', async () => {
  const jwt = await mintToken({ aud: AUDIENCE });

  let err;
  try {
    await verifyToken(jwt, publicKey, {
      audience: 'wrong-service',   // mismatch with token's aud
      issuer: ISSUER,
      algorithms: ALGORITHMS,
    });
  } catch (e) {
    err = e;
  }

  assert.ok(err, 'Should throw for wrong audience');
  assert.strictEqual(err.constructor.name, 'JWTClaimValidationFailed',
    `Expected JWTClaimValidationFailed, got: ${err.constructor.name}`);
  console.log(`  audience rejection: ${err.constructor.name} code=${err.code} claim=${err.claim}`);
});

// ── TEST 3: verifyToken enforces wrong issuer → JWTClaimValidationFailed ─────
test('verifyToken enforces issuer: wrong iss → JWTClaimValidationFailed', async () => {
  const jwt = await mintToken({ iss: ISSUER });

  let err;
  try {
    await verifyToken(jwt, publicKey, {
      audience: AUDIENCE,
      issuer: 'https://evil.example.com',  // mismatch with token's iss
      algorithms: ALGORITHMS,
    });
  } catch (e) {
    err = e;
  }

  assert.ok(err, 'Should throw for wrong issuer');
  assert.strictEqual(err.constructor.name, 'JWTClaimValidationFailed',
    `Expected JWTClaimValidationFailed, got: ${err.constructor.name}`);
  console.log(`  issuer rejection: ${err.constructor.name} code=${err.code} claim=${err.claim}`);
});

// ── TEST 4: verifyToken enforces algorithms allowlist → JOSEAlgNotAllowed ────
test('verifyToken enforces algorithms: RS256 allowlist rejects ES256 token → JOSEAlgNotAllowed', async () => {
  const jwt = await mintToken();  // signed with ES256

  let err;
  try {
    await verifyToken(jwt, publicKey, {
      audience: AUDIENCE,
      issuer: ISSUER,
      algorithms: ['RS256'],  // ES256 token not in allowlist
    });
  } catch (e) {
    err = e;
  }

  assert.ok(err, 'Should throw for disallowed algorithm');
  assert.strictEqual(err.constructor.name, 'JOSEAlgNotAllowed',
    `Expected JOSEAlgNotAllowed, got: ${err.constructor.name}`);
  assert.strictEqual(err.code, 'ERR_JOSE_ALG_NOT_ALLOWED');
  console.log(`  algorithm rejection: ${err.constructor.name} code=${err.code}`);
});

// ── TEST 5: verifyToken rejects tampered token → JWSSignatureVerificationFailed ──
test('verifyToken rejects tampered JWT → JWSSignatureVerificationFailed', async () => {
  const jwt = await mintToken();

  // Flip a character in the signature segment
  const parts = jwt.split('.');
  const sig = parts[2];
  parts[2] = sig[0] === 'A' ? 'B' + sig.slice(1) : 'A' + sig.slice(1);
  const tampered = parts.join('.');

  let err;
  try {
    await verifyToken(tampered, publicKey, {
      audience: AUDIENCE,
      issuer: ISSUER,
      algorithms: ALGORITHMS,
    });
  } catch (e) {
    err = e;
  }

  assert.ok(err, 'Should throw for tampered token');
  assert.strictEqual(err.constructor.name, 'JWSSignatureVerificationFailed');
  assert.strictEqual(err.code, 'ERR_JWS_SIGNATURE_VERIFICATION_FAILED');
  console.log(`  tamper rejection: ${err.constructor.name} code=${err.code}`);
});

// ── TEST 6: verifyToken rejects expired token (no sleep) → JWTExpired ────────
test('verifyToken rejects expired JWT (past exp, no sleep) → JWTExpired', async () => {
  // Set exp 30 seconds in the past to avoid needing to sleep
  const pastExp = Math.floor(Date.now() / 1000) - 30;
  const expiredJwt = await new SignJWT({ sub: 'user123', aud: AUDIENCE, iss: ISSUER, exp: pastExp })
    .setProtectedHeader({ alg: 'ES256' })
    .sign(privateKey);

  let err;
  try {
    await verifyToken(expiredJwt, publicKey, {
      audience: AUDIENCE,
      issuer: ISSUER,
      algorithms: ALGORITHMS,
    });
  } catch (e) {
    err = e;
  }

  assert.ok(err, 'Should throw for expired token');
  assert.strictEqual(err.constructor.name, 'JWTExpired');
  assert.strictEqual(err.code, 'ERR_JWT_EXPIRED');
  console.log(`  expiry rejection: ${err.constructor.name} code=${err.code}`);
});

// ── TEST 7: verifyToken happy path — valid token passes all checks ────────────
test('verifyToken happy path: valid token with correct aud/iss/alg → verified payload', async () => {
  const jwt = await mintToken();

  const { payload } = await verifyToken(jwt, publicKey, {
    audience: AUDIENCE,
    issuer: ISSUER,
    algorithms: ALGORITHMS,
  });

  assert.strictEqual(payload.sub, 'user123', 'payload.sub verified');
  assert.strictEqual(payload.aud, AUDIENCE, 'payload.aud verified');
  assert.strictEqual(payload.iss, ISSUER, 'payload.iss verified');
  assert.ok(typeof payload.iat === 'number', 'payload.iat is a number');
  assert.ok(typeof payload.exp === 'number', 'payload.exp is a number');
  assert.ok(payload.exp > payload.iat, 'exp is after iat');

  console.log(`  verified payload: sub=${payload.sub} aud=${payload.aud} iss=${payload.iss} iat=${payload.iat} exp=${payload.exp}`);
});

// ── TEST 8: createVerifier factory pre-binds options ─────────────────────────
test('createVerifier factory: single-arg verifier rejects wrong aud and accepts correct token', async () => {
  const verifier = createVerifier(publicKey, {
    audience: AUDIENCE,
    issuer: ISSUER,
    algorithms: ALGORITHMS,
  });

  // Should reject token with wrong audience
  const wrongAudJwt = await mintToken({ aud: 'other-service' });
  let err;
  try {
    await verifier(wrongAudJwt);
  } catch (e) {
    err = e;
  }
  assert.ok(err, 'Factory verifier should reject wrong audience');
  assert.strictEqual(err.constructor.name, 'JWTClaimValidationFailed');

  // Should accept token with correct audience
  const validJwt = await mintToken();
  const { payload } = await verifier(validJwt);
  assert.strictEqual(payload.sub, 'user123');
  assert.strictEqual(payload.aud, AUDIENCE);

  console.log(`  createVerifier: rejected wrong-aud (JWTClaimValidationFailed), accepted correct token (sub=${payload.sub})`);
});

