### source/parse-vs-safeparse.test.mjs
```mjs
// GREEN version: correct assertions
import { describe, it } from 'node:test';
import assert from 'node:assert/strict';
import { z } from 'zod';

const userSchema = z.object({
  name: z.string(),
  age: z.number().int().positive(),
  email: z.email(),
});

describe('L0 — parse vs safeParse (Zod 4 canonical seam)', () => {
  it('safeParse(badInput) returns {success:false, error: ZodError} with issues array', () => {
    const result = userSchema.safeParse({ name: 123, age: 'not-a-number', email: 'bad' });
    assert.equal(result.success, false);
    assert.ok(result.error instanceof z.ZodError, 'error should be a ZodError instance');
    assert.ok(Array.isArray(result.error.issues) && result.error.issues.length > 0, 'issues array must be non-empty');
  });

  it('safeParse(goodInput) returns {success:true, data}', () => {
    const result = userSchema.safeParse({ name: 'Alice', age: 30, email: 'alice@example.com' });
    assert.equal(result.success, true);
    assert.deepEqual(result.data, { name: 'Alice', age: 30, email: 'alice@example.com' });
  });

  it('.parse(badInput) throws ZodError', () => {
    assert.throws(
      () => userSchema.parse({ name: 123, age: 'bad', email: 'x' }),
      (err) => {
        assert.ok(err instanceof z.ZodError, 'should be ZodError');
        return true;
      }
    );
  });

  it('ZodError.issues[0] has correct path, code, and message', () => {
    const result = userSchema.safeParse({ name: 123, age: 'not-a-number', email: 'bad' });
    assert.equal(result.success, false);
    const issue = result.error.issues[0];
    assert.deepEqual(issue.path, ['name']);
    assert.equal(issue.code, 'invalid_type');
  });
});

